import type { Story, StoryQuiz } from "@/app/stories";

/* Hand-written stories — 50 per level, each with its own plot, title and
   quiz. Sentence length and vocabulary step up through the years. */

function S(
  id: string,
  title: string,
  emoji: string,
  lexile: number,
  text: string,
  question: string,
  options: [string, string][],
  answer: number,
): Story {
  const quiz: StoryQuiz = {
    question,
    options: options.map(([e, l]) => ({ emoji: e, label: l })),
    answer,
  };
  return { id, title, emoji, lexile, pages: [{ text, emoji }], quiz };
}

const YEAR1: Story[] = [
  S("y1-01", "The Red Hat", "🎩", 200, "Sam the cat has a red hat. He loves his hat a lot. He walks in the park all day. Then the wind blows hard. Whoosh! Off goes the hat! Up and up it flies. It comes down with a flop. It lands on a hen. The hen looks so funny in the hat. Sam laughs and laughs. What a silly day.", "Where did the hat land?", [["🐔","On a hen"],["🪵","On a log"],["🛏️","On a bed"]], 0),
  S("y1-02", "The Big Bus", "🚌", 210, "Here comes the big bus. It is red and very loud. Pip the dog waits at the stop. Beep, beep! The doors open wide. Pip the dog hops on. He finds a seat by the window. The bus goes up the hill. Slow and steady it climbs. Then it goes down the hill. Wheee! Pip loves the bus. He wags his happy tail.", "What did Pip hop on?", [["🚌","A bus"],["🚂","A train"],["⛵","A boat"]], 0),
  S("y1-03", "Pig in the Mud", "🐷", 220, "Pog the pig sees mud. The mud is wet and brown. In he jumps! Splat, splat, splat. Mud goes everywhere. Pog rolls and rolls. He has so much fun. Now Pog is brown, not pink. He is brown from nose to tail. Mum looks at him and gasps. Mum says, time for a bath! But Pog runs away fast. Not yet, not yet!", "What colour was Pog after the mud?", [["🟤","Brown"],["💗","Pink"],["💚","Green"]], 0),
  S("y1-04", "The Lost Sock", "🧦", 230, "Roo cannot find one sock. It is her soft blue sock. She looks under the bed. It is dark down there. She looks in the box. Just toys are in the box. Where is it? She looks and looks. Then she hears a soft purr. The cat has it! He naps on the sock. It is his new toy. Silly cat, says Roo.", "Who had the sock?", [["🐱","The cat"],["🐶","The dog"],["👧","Mum"]], 0),
  S("y1-05", "The Little Egg", "🥚", 240, "Hetty the hen has an egg. It is small and white and smooth. She sits on it all day. She keeps it cosy and warm. She does not move at all. Then tap, tap, tap! A crack! The egg starts to break. Out pops a tiny chick. It is soft and yellow. It says peep, peep. Hetty is so happy. She loves her new chick.", "What came out of the egg?", [["🐤","A chick"],["🐸","A frog"],["🐍","A snake"]], 0),
  S("y1-06", "The Wet Day", "🌧️", 250, "Drip, drop! Rain falls all day. It taps on the roof and pond. Dot the duck is glad. Ducks love rain! She runs out in it. She splashes in a puddle. Splash, splash! Water flies up high. Her friends hide inside. They want to stay dry and warm. Not Dot! She quacks with joy. This is the best day, says Dot.", "How did Dot feel about the rain?", [["😄","Glad"],["😢","Sad"],["😡","Cross"]], 0),
  S("y1-07", "Six Jam Tarts", "🥧", 260, "Bo the bear bakes six jam tarts. They smell so good and sweet. Sniff, sniff. Yum! He cannot wait. He eats one all up. Then two more go in his tummy. Oh no, only three left! Bo feels a bit sad. But then his friends come round. He gives them to his friends. They love them. Sharing is the best, says Bo.", "How many tarts were left for friends?", [["3️⃣","Three"],["6️⃣","Six"],["1️⃣","One"]], 0),
  S("y1-08", "A Trip to the Moon", "🌙", 270, "Max the mouse has a box. It is brown and just his size. He sits in it. He shuts his eyes tight. Zoom! He is off to the moon, in his head! He zooms past the bright stars. He waves to the stars. Hello up there! He has so much fun. Then Mum calls from the door. Dinner time, space mouse! Max hops out, smiling.", "What was the rocket really?", [["📦","A box"],["🚀","A real rocket"],["🛏️","A bed"]], 0),
  S("y1-09", "The Green Frog", "🐸", 280, "A frog sits on a log. The sun is warm and bright. Hop! He jumps in the pond. Splash goes the cool water. The fish swim away fast. The frog grins a big grin. This pond is all mine, he says. He floats and feels so glad. But here come ten ducks! Quack, quack, quack! The frog blinks. Oh dear, not all mine now.", "Where did the frog jump?", [["🪷","In the pond"],["🛏️","On a bed"],["🌳","Up a tree"]], 0),
  S("y1-10", "Bath Time", "🛁", 290, "Bub the pup hates baths. He does not like the water. He hides in the shed. It is dark and quiet there. He hides under the steps. He keeps very still. But Dad finds him every time. In he goes! Splish and splash. Funny thing is, Bub loves the bubbles. He pops them with his paws. He grins a big wet grin. Such a silly pup.", "What did Bub love in the end?", [["🫧","The bubbles"],["🧼","The soap"],["💧","The tap"]], 0),
  S("y1-11", "The Big Carrot", "🥕", 300, "Nib the rabbit digs and digs. The dirt flies up behind him. He finds a big, big carrot. It is orange and long. He pulls and pulls. It will not move! Nib huffs and puffs. His three pals help him. They hold on tight. One, two, three, pull! Pop! Out it comes at last. They all fall down in a heap. They laugh and laugh.", "How did the carrot come out?", [["🤝","Friends helped pull"],["🌧️","Rain washed it out"],["🐦","A bird took it"]], 0),
  S("y1-12", "Snow!", "❄️", 310, "Min wakes up. She rubs her eyes. The world is white! She looks out the window. Snow sits on the car. Snow sits on the dog, too. It is so cold and pretty. Min puts on her red mittens. She runs out to play. She rolls the snow up tight. The first snowball is for Dad. Splat! It hits him on the back. Dad laughs out loud.", "Who got hit by the snowball?", [["👨","Dad"],["🐶","The dog"],["🚗","The car"]], 0),
  S("y1-13", "The Ant and the Bun", "🐜", 320, "One small ant finds one big bun. It sits on the path. It is as big as a house! The ant cannot lift it. She calls her nest for help. Come quick, come quick! One hundred ants march out. They line up nose to tail. They push and pull together. Crumb by crumb, they take it home. By tea time, the bun is all gone. Yum!", "How many ants came to help?", [["💯","One hundred"],["🔟","Ten"],["1️⃣","One"]], 0),
  S("y1-14", "Where Is Kit?", "🐱", 330, "Kit the kitten is lost. Mum looks all around. Is she in the cup? Too small! A kitten cannot fit there. Is she in the shoe? No. Just a sock is in there. Where can she be? Listen... purr, purr. A soft sound comes from the hat. There she is, asleep in the sun hat! She is curled up tight. What a cosy nap.", "Where was Kit sleeping?", [["👒","In the sun hat"],["👟","In the shoe"],["☕","In the cup"]], 0),
  S("y1-15", "The Fast Snail", "🐌", 340, "Sid the snail wants to be fast. He is so slow all day. He has a clever plan. He gets on the dog's back. He holds on tight. The dog runs to the gate. Zoom they go! Wheee! The wind blows past Sid. His little house wobbles. Now Sid is the fastest snail in town. He grins a big grin. That was so much fun!", "How did Sid go fast?", [["🐶","He rode the dog"],["🚗","He drove a car"],["💨","He ran"]], 0),
  S("y1-16", "Ten Red Apples", "🍎", 350, "Ten red apples on the tree. They hang up high and round. The wind blows one down. Plop! It hits the soft grass. Then two more come down. Plop, plop, plop! Now seven hang on the tree. Tam comes with her big basket. She picks them all up. Every one goes in. Tam takes them home to bake. What did Tam make? She made apple pie!", "What did Tam make?", [["🥧","Apple pie"],["🥤","Apple juice"],["🍰","A cake"]], 0),
  S("y1-17", "The Night Owl", "🦉", 360, "All day, Olly the owl sleeps. He naps in his cosy tree. The sun is up and bright. But Olly stays fast asleep. At night, he wakes up! He stretches his big wings. He hoots at the moon. Hoot, hoot! He counts the stars one by one. He flies all night long. When the sun comes up, Olly yawns. Time for bed. Good night, sun!", "When does Olly wake up?", [["🌙","At night"],["🌅","At sunrise"],["🕛","At lunch"]], 0),
  S("y1-18", "The Red Boat", "⛵", 370, "Jen has a little red boat. It is small and shiny. She sails it in the tub. The water is warm and soapy. The boat floats this way and that. A big wave comes! It is just Dad's hand! Splash! The boat flips right over. Oh no, says Jen. She reaches in fast. Jen saves it just in time. All safe now. She sails it again.", "Where did Jen sail her boat?", [["🛁","In the tub"],["🌊","In the sea"],["🪣","In a bucket"]], 0),
  S("y1-19", "Lost Tooth", "🦷", 380, "Wiggle, wiggle. Ben's tooth is loose. It moves back and front. He pokes it with his tongue. Then he bites his toast. Crunch! Pop! The tooth is out! It is small and white. Ben grins a gappy grin. He runs to show Mum. He puts it in a cup. He sets it by his bed. Tonight the tooth fairy will come! Ben cannot wait to sleep.", "Where did Ben put his tooth?", [["☕","In a cup"],["📦","In a box"],["🧦","In a sock"]], 0),
  S("y1-20", "The Mud Cake", "🎂", 390, "Pia makes a cake of mud. She pats it round and flat. She adds a leaf on top. It looks just like a real cake. Yum, yum, she says, just for fun. She does not eat it, of course. Then up runs the dog. The dog takes a real bite! Yuck! He shakes his head. Silly dog! Pia laughs and laughs. That cake is not for you!", "Who took a real bite?", [["🐶","The dog"],["👧","Pia"],["🐦","A bird"]], 0),
  S("y1-21", "Hop, Bug, Hop!", "🦗", 400, "A bug hops on my hand. It tickles me a lot. It hops on my hat. Then it hops on my nose! I go cross-eyed to see it. Hop, bug, hop. It is so small and quick. I stay still as can be. Now it hops away home. Off it goes to the grass. Bye bye, little bug. Come back and play one day.", "Where did the bug hop last?", [["🏠","Away home"],["👃","On a nose"],["🎩","On a hat"]], 0),
  S("y1-22", "The Sun and the Hat", "☀️", 410, "The sun is hot, hot, hot. It shines down all day. Gus the pig needs a hat. His head is much too warm. He trots off to the shop. The shop has big hats and small hats. There are so many to see. Gus tries a few on. Gus picks the big one. It fits just right. Now the sun cannot get him! Gus stays cool and happy.", "Why did Gus need a hat?", [["☀️","The sun was hot"],["🌧️","It was raining"],["🎉","For a party"]], 0),
  S("y1-23", "Five Little Peas", "🫛", 420, "Five peas sit in a pod. They are small and green and round. It is a snug little bed. They sleep there side by side. The sun shines warm each day. One day the pod pops open! Snap! The peas roll out. One, two, three, four, five. They bounce on the soft ground. Off they roll to see the world. Goodbye, little pod! What fun.", "How many peas were in the pod?", [["5️⃣","Five"],["3️⃣","Three"],["🔟","Ten"]], 0),
  S("y1-24", "The Drum", "🥁", 430, "Tom got a drum. He banged it right away. Bang, bang, bang! It was so loud. The cat ran out the door. Bang, bang! Dad held his ears. Too loud, Tom, too loud! So Tom played soft. Tap-tap-tap, nice and gentle. The sound was sweet and low. Now the cat came back to listen. He sat by the drum. Tom smiled. Soft is best, he said.", "How did Tom play at the end?", [["🤫","Softly"],["💥","Very loud"],["🚫","Not at all"]], 0),
  S("y1-25", "Up the Tree", "🌳", 440, "The kite is stuck up the tree. It is way up high. Jo cannot reach it. She jumps but it is too tall. Dad cannot reach it. He tries and tries. But Coco the monkey can! Up she goes, quick and quick. She climbs from branch to branch. Down comes the kite! Jo claps her hands. Bananas for Coco! She eats them with a happy grin.", "Who got the kite down?", [["🐵","Coco the monkey"],["👨","Dad"],["👧","Jo"]], 0),
  S("y1-26", "The Yellow Bus Stop", "🚏", 450, "Every day, Gran waits at the yellow bus stop. She likes to go to town. Today, the bus is late. Gran looks up the road. Gran taps her foot. Where can it be? She waits and waits. Here it comes at last! The bus pulls up slow. The driver says sorry. Gran asks him why. A sheep sat on the road! Gran laughs. Oh, a sheep!", "Why was the bus late?", [["🐑","A sheep sat on the road"],["🌧️","It was raining"],["⛽","It needed petrol"]], 0),
  S("y1-27", "The Best Nest", "🪺", 460, "Two birds build a nest. They work hard all day. They use grass. They tug it bit by bit. They use string. They weave it round and round. They use a bit of red wool from Gran's hat! It makes the nest snug. The nest is soft and warm. It sits high in the tree. Three eggs fit just right. The birds are very proud.", "What red thing went in the nest?", [["🧶","Wool from a hat"],["🍎","An apple"],["🌹","A rose"]], 0),
  S("y1-28", "Splash at the Pool", "🏊", 470, "Lin is at the pool. The sun is warm today. The water looks deep. It makes her feel scared. She holds the rail tight. One step, two steps. The water is cool. Splash! She lets go at last. She kicks and kicks her legs. Her arms push the water. She moves all by herself! Look, Mum, I can swim! Mum claps and cheers. Well done, Lin!", "What did Lin learn to do?", [["🏊","Swim"],["🚴","Ride a bike"],["🤸","Do a flip"]], 0),
  S("y1-29", "The Sandwich Thief", "🥪", 480, "Dad made a big sandwich. It had ham and cheese. He put it on the bench. It looked so good. He went to get juice. He was gone for a bit. When he came back, half was gone! Who took it? Dad looks down. Crumbs led to the dog house. The dog peeks out, licking his lips. Dad laughs. Case closed. You cheeky dog, says Dad.", "Who took the sandwich?", [["🐶","The dog"],["🐦","A seagull"],["👶","The baby"]], 0),
  S("y1-30", "A Star for Tea", "⭐", 490, "Zoe sees a star fall in the garden. It glows in the dark. She runs out with her net. She wants to catch it. Is it under the rose? She looks low and slow. Is it in the pond? No, just fish there. Then she sees a soft green light. It is a glow worm! It blinks at her. Stay for tea, little star. Zoe smiles.", "What was the fallen star?", [["🪱","A glow worm"],["⭐","A real star"],["💡","A torch"]], 0),
  S("y1-31", "The Wrong Boots", "👢", 500, "Ed put on his boots. He was in a big rush. Left boot, right boot. There, all done! But they felt funny! His toes felt all wrong. He tried to walk. Wobble, wobble. He looked down at his feet. The boots were on the wrong feet! Oh, said Ed. He sat down to fix them. Swap! Now they feel just right. Now Ed can run!", "Why did the boots feel funny?", [["🔄","They were on the wrong feet"],["💧","They were wet"],["🐜","Ants were inside"]], 0),
  S("y1-32", "Bee and the Jam", "🐝", 505, "A bee smells jam. The smell is sweet and nice. She flies in the window. Buzz, buzz, buzz. She looks all around. She lands on the toast! Right on the red jam. Shoo, bee, shoo! Gran waves her hand. She does not want to hurt it. Gran opens the window wide. Out you go, little bee. Off goes the bee with a happy buzz. Bye bye, bee!", "What did the bee smell?", [["🍓","Jam"],["🌹","A rose"],["🍯","Honey"]], 0),
  S("y1-33", "The Little Train", "🚂", 510, "The little train chugs up the hill. The hill is steep and long. It is hard work. The train tries hard. Puff, puff, puff. Slow and slow it goes. I think I can, I think I can. It will not give up. At the top, it cheers! Hooray, I did it! It is so proud. Then wheee, all the way down. Fast and fun. What a ride!", "What did the train say going up?", [["💪","I think I can"],["😴","I want to sleep"],["🛑","I give up"]], 0),
  S("y1-34", "Hide and Seek", "🙈", 515, "Pim hides behind the door. He stays very still. Tess hides in the big plant. She holds her breath. Dad counts to ten. One, two, three... ready or not! He looks all around. He finds Pim fast. There you are, Pim! But where is Tess? Dad cannot see her. He looks high and low. Then, hee hee hee! Only her giggle gives her away! Found you, Tess!", "What gave Tess away?", [["😄","Her giggle"],["👟","Her shoes"],["🐱","The cat"]], 0),
  S("y1-35", "The Pancake Flip", "🥞", 520, "Mum flips the pancake. Up it goes! It spins in the air. It does not come down. Where is it? Mum looks left and right. Look up. There it is! It is stuck on the lamp! It hangs up high. Oh dear, says Mum. Dad gets the steps. He climbs up nice and slow. He pulls it down at last. Breakfast is saved! Everyone laughs and eats.", "Where did the pancake land?", [["💡","On the lamp"],["🍽️","On the plate"],["🐶","On the dog"]], 0),
  S("y1-36", "Big Ted's Day Out", "🧸", 525, "Big Ted fell out of the pram. He landed on the path. He sat by the path all day. The sun went up and down. People walked by him. A kind girl saw him there. She picked him up gently. She put him on the wall. Where can Ana be? At five, Ana came back. Ted! She ran to him. She hugged him all the way home.", "Where did the girl put Ted?", [["🧱","On the wall"],["🗑️","In the bin"],["🌳","In a tree"]], 0),
  S("y1-37", "The Singing Kettle", "🫖", 530, "The kettle sings when tea is ready. Wheee! It whistles loud and clear. Gran sings back to it. La la la! The dog howls along. Oooo, oooo! What a happy sound. The cat does not like it. The cat leaves the room. Too loud for me, says the cat. Gran laughs and pours the tea. Every tea time is a concert at Gran's. What a merry house.", "Who leaves during the concert?", [["🐱","The cat"],["🐶","The dog"],["👵","Gran"]], 0),
  S("y1-38", "One Windy Day", "💨", 535, "The wind took Dad's cap. Whoosh! Off it flew. Then it took the wash from the line! Up and away it all went. Socks flew like little flags. They danced in the sky. Tilly caught them with the net. Swish, swish, got you! She ran here and there. What about the cap? The cap landed on the goat! The goat blinked and chewed. Tilly laughed out loud.", "Who wore the cap at the end?", [["🐐","The goat"],["👨","Dad"],["👧","Tilly"]], 0),
  S("y1-39", "The Shy Crab", "🦀", 540, "A crab hides under a shell. It is small and snug. Kids dig near him. Dig, dig, dig in the sand. He moves to a new shell. He scuttles sideways. More kids! They run and play. Oh no, says the crab. He is tired of all the noise. At last he finds a quiet pool. The water is still. Ah, says the crab. Home. He rests at last.", "What was the crab looking for?", [["🤫","A quiet spot"],["🍕","Food"],["👫","Friends"]], 0),
  S("y1-40", "Granny's Glasses", "👓", 545, "Granny lost her glasses. She looked everywhere. She looked in the bag. Just keys were in there. She looked on the shelf. Not there at all. Oh dear, where are they? We giggled and giggled. We could see them! Granny, look up! They were right there. They sat on her head the whole time. Granny laughed too. Silly me, she said. Thank you, my dears!", "Where were the glasses?", [["👵","On Granny's head"],["👜","In the bag"],["📚","On the shelf"]], 0),
  S("y1-41", "The Brave Ladybird", "🐞", 550, "A ladybird lands on the slide. She is red with black spots. Kids zoom past her fast. Whee, down they go! She does not fly away. She holds on tight. She climbs to the very top. Up and up she goes. It takes a long time. Then she slides down on one wing. Wheee! Down she goes like the kids. What a brave little ladybird. Again, again!", "What did the ladybird slide on?", [["🛝","The slide"],["🍃","A leaf"],["🌈","A rainbow"]], 0),
  S("y1-42", "Soup for a King", "🍲", 555, "Cook made soup for the king. It steamed in the big bowl. The king sipped a bit. Too hot! He pulled a face. He huffed and puffed at it. Blow, blow, blow. He waited and waited. He tapped his royal foot. At last the soup was cool. At last, one royal slurp. Mmm, said the king. So good! More, please! Cook smiled and filled the bowl.", "What was wrong with the soup at first?", [["🔥","Too hot"],["🧊","Too cold"],["🧂","Too salty"]], 0),
  S("y1-43", "The Moon in the Pond", "🌝", 560, "Pup sees the moon in the pond. It is round and white. He barks at it. Woof, woof, woof! He wants that shiny ball. He splashes in to get it. Splash, splash! The moon breaks into bits! It wobbles all around. Pup whines and looks sad. Where did it go? Then the water goes still. The moon comes back, round and bright. Moon is back! Pup wags his tail.", "Where did Pup see the moon?", [["🪷","In the pond"],["🪞","In a mirror"],["🥛","In his bowl"]], 0),
  S("y1-44", "New Shoes", "👟", 565, "Kai has new shoes. He got them today. They are red with white laces. He loves them a lot. He runs round the yard ten times! One, two, three... so fast! Fast shoes, he says. He jumps and skips in them. He does not want to take them off. At bed time, the shoes sit by his pillow. Goodnight, shoes, says Kai. He cannot wait for tomorrow.", "Where were the shoes at bedtime?", [["🛏️","By his pillow"],["🚪","By the door"],["👣","On his feet"]], 0),
  S("y1-45", "The Honey Pot Hat", "🍯", 570, "Little Bear got his head stuck in the honey pot. It was dark inside. He could not see at all. Bump! He walked into the table. Bump! Then the door. Ow, ow, ow! Mama Bear came to help. She held him tight. She pulled and pulled. Pop! Off it came. Free at last, and very sticky. Honey was all over his nose. They both laughed and laughed.", "What was stuck on Little Bear's head?", [["🍯","A honey pot"],["🎩","A hat"],["🪣","A bucket"]], 0),
  S("y1-46", "The Quiet Library", "🤫", 575, "Shh! says the sign. The library is very quiet. Mo tiptoes in. Soft, soft on his toes. He looks at the books. So many to choose. He picks a book about dragons. Big red dragons that fly! He sits down to read. A page goes flip. It sounds so loud! Mo holds his breath. The librarian smiles at him. It is fine, Mo. Books like quiet readers.", "What was Mo's book about?", [["🐉","Dragons"],["🚒","Fire trucks"],["🐠","Fish"]], 0),
  S("y1-47", "Ducks in a Row", "🦆", 580, "Mama duck crosses the road. She walks slow and proud. Five ducklings follow in a line. Peep, peep, peep! They are soft and fluffy. Cars stop to let them go. The road is busy today. A man waves his hat. Stop for the ducks! Everyone waits and smiles. They wait till the last fluffy tail hops up the kerb. Safe at last! Off waddle the happy ducks.", "How many ducklings followed?", [["5️⃣","Five"],["2️⃣","Two"],["🔟","Ten"]], 0),
  S("y1-48", "The Magic Word", "🪄", 585, "Ben wants a biscuit. He looks at the tin. Gran waits and waits. She does not open it. Ben thinks hard. What does he need to say? Then he knows! Please! he says with a smile. Gran smiles big and bright. There it is! The tin opens with a click. Ben takes a yummy biscuit. Thank you, Gran! Some words are little keys, says Gran. They open doors.", "What was the magic word?", [["🙏","Please"],["✨","Abracadabra"],["🍪","Biscuit"]], 0),
  S("y1-49", "Winter Coats", "🧥", 590, "The pond froze today. It went hard and shiny. The ducks slid on it like skaters! Whee, round and round they went. It looked so much fun. Lena watched and laughed. Then Lena threw them seeds. Peck, peck, peck went the ducks. It was cold outside. So she zipped her coat right up. Even ducks need winter coats, said Dad. They have feathers! Warm and snug, just right.", "What do ducks use as winter coats?", [["🪶","Feathers"],["🧥","Wool coats"],["🧣","Scarves"]], 0),
  S("y1-50", "Goodnight, Farm", "🌾", 595, "The sun goes down on the farm. The sky turns pink and gold. It is time for bed. The hens climb to their roost. Cluck, cluck, goodnight. The cow lies in the hay. It is soft and warm there. The dog curls by the gate. He keeps one ear up. The farmer waves to them all. Goodnight, farm. He shuts the door. See you at sunrise.", "Where did the cow sleep?", [["🌾","In the hay"],["🛏️","In a bed"],["🚜","On the tractor"]], 0),
];

const YEAR2: Story[] = [
  S("y2-01", "The Runaway Kite", "🪁", 440, "Bea made a kite with paper and string. She painted it red and blue. At the park, the wind grabbed it and pulled hard. The string slipped from her hand! The kite danced over the trees. Bea ran and called for help. A kind man on a ladder caught it. He passed it gently back to her. Bea said thank you and smiled. She held on tight after that, all afternoon.", "Who caught the kite?", [["🧑‍🔧","A man on a ladder"],["🐦","A bird"],["👮","A police officer"]], 0),
  S("y2-02", "The Great Snail Race", "🐌", 450, "On Sunday the garden held a snail race. Shelly was the smallest snail, and everyone giggled at her. She felt a little shy. But Shelly did not stop once. She kept going, slow and steady. The big snails napped in the warm sun. Slowly, slowly, she slid past them all. Her tiny trail glistened on the path. At last she crossed the line first! Everyone cheered, and Shelly grinned with pride.", "Why did Shelly win?", [["🐢","She never stopped"],["💨","She was fastest"],["🍀","She was lucky"]], 0),
  S("y2-03", "The Wobbly Tooth", "🦷", 460, "Finn had a wobbly tooth. It moved when he touched it. He wiggled it at breakfast. He wiggled it at school. He could not stop thinking about it. At lunch he bit a crunchy apple and, pop, out it came! Finn laughed with surprise. He kept the little tooth in his pocket. He put it under his pillow that night. In the morning he found a shiny coin and grinned.", "What made the tooth come out?", [["🍎","A crunchy apple"],["🥕","A carrot"],["🍞","Soft bread"]], 0),
  S("y2-04", "The Sandcastle King", "🏰", 470, "At the beach, Ollie built a giant sandcastle. It had four towers and a deep moat. He worked hard in the warm sun. A wave crept closer and closer to the wall. Crash! Half the castle washed away. Ollie did not cry. He looked at the wet sand and smiled. He laughed and shouted, now I will build it even bigger! So he started again with a happy heart and a big spade.", "What knocked the castle down?", [["🌊","A wave"],["🐶","A dog"],["💨","The wind"]], 0),
  S("y2-05", "Where Is the Honey?", "🍯", 480, "Bo the bear looked in the cupboard for honey, but the pot was empty. His tummy rumbled with hunger. Then he spotted something sticky on the floor. He followed a line of sticky paw prints across the room. They led him through the kitchen and down the hall. They led to his little sister, fast asleep. She had the pot in her arms and honey on her nose! Bo laughed and tickled her toes.", "Who took the honey?", [["🐻","Bo's little sister"],["🐝","The bees"],["🐭","A mouse"]], 0),
  S("y2-06", "The Rainbow Hunt", "🌈", 490, "After the rain, Roo saw a rainbow over the hill. It shone in bright, pretty colours. She raced to find where it touched the ground. Over the bridge she ran, then past the barn. Through the wet grass her boots splashed and squelched. She was sure she would find treasure. The rainbow slowly faded away in the sky. But Roo found a field full of golden sunflowers instead. She picked one and smiled.", "What did Roo find at the end?", [["🌻","Sunflowers"],["💰","Gold coins"],["🦄","A unicorn"]], 0),
  S("y2-07", "The Brave Night Light", "🔦", 500, "Thunder boomed outside and the lights went out. The whole house was dark. Pip felt scared in the dark room. His heart beat fast. Then he remembered his torch under the pillow. He reached out and grabbed it. Click! A warm circle of light filled the room. Pip felt much braver now. He made shadow bunnies on the wall with his hands. He played until the storm rolled away and the rain stopped.", "What did Pip use in the dark?", [["🔦","A torch"],["🕯️","A candle"],["📱","A phone"]], 0),
  S("y2-08", "The Mystery Seed", "🌱", 505, "Dot planted a mystery seed in the garden. She watered it every single day. She wondered what it would be. A green shoot appeared from the soil. Then leaves grew as big as plates! The plant climbed and curled along the ground. By summer it was a pumpkin vine. It had one enormous orange pumpkin. Dot was so proud of it. Her whole family carved it together for the autumn fair, and everyone smiled.", "What grew from the seed?", [["🎃","A pumpkin"],["🌹","A rose"],["🌳","An oak tree"]], 0),
  S("y2-09", "The Backwards Day", "🔄", 510, "On Tuesday, Milo did everything the silly way. He put his jumper on backwards. It looked very funny. Then he ate dinner at breakfast time, just for fun. He giggled at his plate. He even walked to school backwards, with Mum guiding him by the hand. People stopped and laughed in the street. His teacher laughed too and said, shall we count backwards today? Ten, nine, eight, the whole class joined in happily.", "What did Milo eat at breakfast time?", [["🍝","Dinner"],["🥞","Pancakes"],["🍦","Ice cream"]], 0),
  S("y2-10", "Captain Mop", "🧹", 515, "When the kitchen flooded, water spread across the floor. Jess grabbed the mop and shouted, I am Captain Mop! She felt brave and strong. She swished left, she swished right. Splash went the soapy water. Her brother manned the towels behind her. They worked hard as a team. By the time Mum came home, the sea was gone. The floor shone like new. Two soggy heroes took a bow and laughed out loud.", "What did Jess call herself?", [["🧹","Captain Mop"],["🦸","Super Jess"],["👩‍✈️","Pilot Jess"]], 0),
  S("y2-11", "The Penguin's Scarf", "🧣", 520, "Pearl the penguin found a stripy scarf on the ice. It was soft and bright. It was longer than three penguins! She thought hard about what to do. She wore it as a hat. She wore it as a tail. It still felt far too long. Then she saw six little chicks shivering in the cold wind. In the end, she wrapped it around six shivering chicks, and everyone was warm and cosy together.", "Who ended up wearing the scarf?", [["🐤","Six chicks"],["🐧","Pearl alone"],["🦭","A seal"]], 0),
  S("y2-12", "The Loose Wheel", "🛴", 525, "Theo's scooter rattled all the way down the lane. Rattle, rattle, clunk! Something was loose. The back wheel rolled off into the roses. Theo stopped and stared. He did not know what to do. So he ran to find Grandpa. Grandpa fetched his big toolbox. He showed Theo the shiny spanner. Together they turned it round and round. They fixed it tight again. The only sound left was wheee as Theo rolled away.", "Who helped fix the scooter?", [["👴","Grandpa"],["👩","Mum"],["🧑‍🔧","A mechanic"]], 0),
  S("y2-13", "A Home for Hoppy", "🏡", 530, "A tiny frog kept sleeping in Lara's watering can. He looked so cosy in there. Every morning she tipped him gently into the grass. And every night he climbed back in again. Lara did not mind, but he needed a real home. So Lara built him a little pond from an old basin. She added a stone for sunbathing in the sun. The frog hopped in happily. The watering can stayed empty after that.", "Where did the frog keep sleeping?", [["🪣","In the watering can"],["👟","In a shoe"],["📮","In the postbox"]], 0),
  S("y2-14", "The Missing Piece", "🧩", 535, "The puzzle had five hundred pieces, and one was missing. Everyone wanted to finish it. The whole family searched the floor. They looked high and low. Under the sofa they found a button, a raisin and one slipper. But there was no puzzle piece anywhere. They started to give up. Then baby Ada giggled in her chair. Everyone turned to look at her. There it was, stuck to her sticky hand! They all laughed together.", "Who had the missing piece?", [["👶","Baby Ada"],["🐶","The dog"],["🛋️","The sofa"]], 0),
  S("y2-15", "The Singing Bus Driver", "🎤", 540, "Mr Olu drove the school bus, and he sang every morning. He had a big, happy voice. Stop one, he sang hello to everyone. Stop two, he sang about the rain. The children loved his songs. Soon the whole bus sang along with him. They clapped and tapped their feet. Parents waited at the bus stop and smiled. They said it was the happiest traffic jam in town. Every morning felt like a party.", "What did everyone do on the bus?", [["🎶","Sang together"],["😴","Slept"],["📚","Did homework"]], 0),
  S("y2-16", "The Apple Thief", "🍏", 545, "Apples kept vanishing from the lowest branch of the tree. Nobody knew why. Dad blamed the birds. Mia was not so sure. She set up her teddy bear as a guard by the tree. Then she watched and waited. From the window that night, they kept very still. At last they saw the real thief. It was a round little hedgehog, rolling an apple home like a tiny wheelbarrow! Mia laughed with delight.", "Who was taking the apples?", [["🦔","A hedgehog"],["🐦","Birds"],["🧸","The teddy"]], 0),
  S("y2-17", "Race to the Letterbox", "📮", 550, "Every day, Jip the dog raced the postwoman to the letterbox. He ran as fast as he could. Every day, she won by a whisker. Jip never gave up trying. On Friday she brought a parcel and walked extra slow. Jip got there first at last! He wagged his tail with joy. What was inside the parcel? Dog biscuits, just for him. She had planned it all along, with a kind little smile.", "What was in Friday's parcel?", [["🦴","Dog biscuits"],["📚","Books"],["🧦","Socks"]], 0),
  S("y2-18", "The Cloud Zoo", "☁️", 555, "Lying on the hill, Noor and her brother watched clouds drift by. The sky was big and blue. That one is an elephant, said Noor, pointing up. That one is a dragon eating toast! They laughed at all the silly shapes. The best cloud of all looked exactly like their cat. They could not stop giggling. When they got home, the real cat was waiting. The real cat looked quite offended, and they laughed again.", "What were the children watching?", [["☁️","Clouds"],["🐘","Real elephants"],["📺","Television"]], 0),
  S("y2-19", "One Boot Short", "🥾", 560, "The class was going puddle-jumping, but Sami could only find one boot. He searched everywhere for the other one. He hopped on one leg to show Miss May. She had a clever idea. She opened the lost-and-found box and looked inside. There were seventeen left boots! Sami could not believe it. He picked a bright red one and pulled it on. It fitted just right. Best puddle splash of the day, no contest, everyone agreed.", "How many left boots were in the box?", [["🔢","Seventeen"],["2️⃣","Two"],["💯","A hundred"]], 0),
  S("y2-20", "The Window Garden", "🪟", 565, "Flat seven had no garden, so Ana grew one on the windowsill. She loved her little plants. She grew tomatoes, mint, and one tall sunflower. The sunflower grew taller than the window! Ana watered them every day with care. The neighbours saw her green windowsill and smiled. They started copying her good idea. Soon pots appeared on every ledge. By July, the whole building bloomed like a striped, leafy birthday cake. Everyone felt cheerful.", "Where did Ana grow her garden?", [["🪟","On the windowsill"],["🏞️","In a park"],["🏖️","At the beach"]], 0),
  S("y2-21", "Ferry the Tortoise", "🐢", 570, "Ferry the tortoise escaped every single day. He was very good at it. Over the lawn he crawled, then under the fence. He went straight into next door's lettuce. Mr Patel was not happy. He built the fence higher and stronger. But Ferry just dug lower under it. They could not stop him. At last the two neighbours had a clever idea. They planted a lettuce patch on the fence line and shared him happily.", "How did the neighbours solve the problem?", [["🥬","They shared a lettuce patch"],["🧱","They built a wall"],["🔒","They locked Ferry in"]], 0),
  S("y2-22", "The Birthday Mix-Up", "🎂", 575, "Gran asked the baker for a cake that said Happy Birthday Stanley. The baker was very busy that day. He heard the name wrong by mistake. He wrote it down quickly. At the party, the cake came out at last. Everyone looked at the writing. The cake said Happy Birthday Standley! There was a silly extra letter. Everyone laughed so hard they cried. Stanley laughed loudest of all. He declared Standley his official party name, forever.", "What was wrong with the cake?", [["✏️","The name was spelled wrong"],["🍫","Wrong flavour"],["🕯️","Too many candles"]], 0),
  S("y2-23", "Storm in a Teacup", "🍵", 580, "Great Aunt Vi said there was a storm in her teacup. Lily did not understand. She leaned over and peered in. The tea swirled where Vi had stirred it. It went round and round like a tiny brown sea. Lily thought it was wonderful. They found a tiny crumb to use as a boat. They sailed a crumb boat on it. They played until the storm calmed down. Then the biscuit ship sank, deliciously.", "What did they sail on the tea?", [["🍪","A crumb boat"],["⛵","A paper boat"],["🥄","A spoon"]], 0),
  S("y2-24", "The Hiccup Cure", "😮", 585, "Dev had the hiccups all through maths. Hic! He could not make them stop. The class tried everything to help. They tried holding their breath. They tried drinking water upside down. Tom gave him a tiny fright. But nothing worked at all. Dev was getting tired of hiccups. Then Miss had an idea. Spell hiccup backwards, she said kindly. Dev thought so hard about the letters. The hiccups gave up and quietly left.", "What finally cured the hiccups?", [["🔤","Spelling backwards"],["💧","Drinking water"],["😱","A fright"]], 0),
  S("y2-25", "The Bridge Troll's Day Off", "🌉", 590, "The troll under the bridge put up a sign: On Holiday. The goats read it slowly. They trotted across the bridge, feeling confused. Where was the grumpy roar today? It was strangely quiet. So they went off to look for him. They found the troll at the beach. He was building a sandcastle bridge in the sun. He had a little sand troll under it. Even trolls need a rest, he said, with a happy yawn.", "Where was the troll?", [["🏖️","At the beach"],["🌉","Under the bridge"],["🏔️","On a mountain"]], 0),
  S("y2-26", "The Talking Parrot Problem", "🦜", 595, "Grandad taught his parrot to say good morning. The parrot was a clever bird. But the parrot learned something extra all by itself. It learned Grandad's snore! Every night at eight, the parrot started up. It snored loudly from its perch in the corner. The sound was so funny and loud. Everyone in the house heard it. They shouted goodnight to make it stop. Now the whole family goes to bed exactly on time, and laughs.", "What extra sound did the parrot learn?", [["😴","Grandad's snore"],["🎵","A song"],["🔔","The doorbell"]], 0),
  S("y2-27", "Pancakes for the Queen", "👑", 600, "The sign at the café said: The Queen Ate Here. Tilly read it twice. Wow, said Tilly, feeling very excited. She ordered the same pancakes the Queen had. She waited at her table. They came with lemon and a paper crown. Tilly put the crown on her head at once. She wore the crown all through lunch. She ate like royalty, slow and grand. She left a thank-you note signed Queen Tilly the First.", "What came with the pancakes?", [["👑","A paper crown"],["🍓","Strawberries"],["🎈","A balloon"]], 0),
  S("y2-28", "The Shadow Puppy", "🐕", 605, "Every sunny day, a black puppy followed Ido everywhere he went. It never made a sound. It copied his jumps. It copied his cartwheels too. But it vanished under the clouds. Ido thought hard about this funny puppy. My shadow is a puppy, Ido told his mum. She smiled at his idea. So they taught it tricks together in the garden. Sit, shadow, sit! It always obeyed best at noon, when the sun was high.", "When did the shadow puppy obey best?", [["🕛","At noon"],["🌙","At night"],["🌧️","In the rain"]], 0),
  S("y2-29", "The Sock Octopus", "🐙", 610, "The lost socks from the laundry had to go somewhere. There were so many odd ones. Nana had a clever plan. She sewed eight odd socks into an octopus. She gave him bright button eyes. Olly thought he was wonderful. Olly named him Captain Toes. He carried him everywhere. Now whenever a sock goes missing, Olly is not sad. He checks the laundry basket and grins. The Captain is recruiting again, he says happily.", "What did Nana make from lost socks?", [["🐙","An octopus"],["🐍","A snake"],["🎈","A balloon"]], 0),
  S("y2-30", "Cress Heads", "🌿", 615, "The class grew cress in eggshells. They drew funny faces on each one. They watered them carefully every day. By Friday, every egg had wild green hair! The children laughed at the silly hairdos. They gave them haircuts with little scissors. Snip, snip went the cress. Then they ate the trimmings in sandwiches at lunch. They tasted fresh and peppery. Benny's egg got a tall mohawk. It was the proudest egg in the whole school.", "What was the cress used for?", [["🥪","Sandwiches"],["🍵","Tea"],["🥗","Nothing"]], 0),
  S("y2-31", "The Upside-Down Bat", "🦇", 620, "A small bat moved into the garden shed. He found a cosy beam to hang from. He hung upside down all day long. So he saw everything upside down. To him, the family picnicked on the ceiling. The dog seemed to fly through the air. The whole world looked topsy-turvy to him. Then one day Pia came outside to play. She hung from the climbing frame to wave hello. The bat finally saw someone the right way up.", "How did the bat see the world?", [["🙃","Upside down"],["😴","With eyes closed"],["🕶️","In the dark only"]], 0),
  S("y2-32", "The Whistling Kettle Choir", "🎶", 625, "Gran's kettle whistled in C every morning. It made a cheerful sound. Next door's kettle whistled higher than hers. The cafe's kettle was deepest of all. Each one had its own special note. One cold morning something special happened. All three boiled at exactly the same time. The street had a kettle choir! The notes sang out together in the frosty air. Gran loved it. She swears they practise when nobody is listening at night.", "What did the three kettles make?", [["🎶","A kettle choir"],["☕","Three teas"],["🌫️","Fog"]], 0),
  S("y2-33", "Detective Dot and the Crumbs", "🔍", 630, "Someone ate the last biscuit, and nobody owned up. Detective Dot took the case. She looked for clues everywhere. Dot found crumbs on the rug. She found crumbs on the stairs too. Then she found crumbs on a certain little brother's chin. Case solved? Not quite, she thought. She looked more closely. The chin belonged to Dad! He had to pay a fine. He bought two new packets of biscuits. Dot ate the first one happily.", "Where were the final crumbs found?", [["🧔","On Dad's chin"],["👶","On the baby"],["🐶","On the dog"]], 0),
  S("y2-34", "The Paper Boat Fleet", "⛵", 635, "After the storm, the gutter ran like a river. Water rushed along the street. Sami and Lin had a brilliant idea. They folded twelve paper boats together. They raced them all the way to the drain. Some boats sank straight away. One got stuck on a leaf island. They cheered their favourites on. The winner was a tiny red one. It sailed the whole street, bobbing along. It was awarded a shiny bottle-cap trophy by the children.", "What was the trophy?", [["🍾","A bottle cap"],["🏆","A gold cup"],["🎖️","A medal"]], 0),
  S("y2-35", "The Yawning Lion", "🦁", 640, "At the zoo, the lion opened his mouth wide. He yawned a yawn so big that Leila yawned back. She could not help it. Then the zookeeper yawned too. Then a whole school group yawned. They went one after another like dominoes. The yawns spread all around the zoo. Everyone covered their mouths and laughed. The lion watched it all, very pleased with himself. Then he curled up for the nap he had started.", "What spread through the zoo?", [["😪","Yawns"],["😂","Laughter"],["🎵","A song"]], 0),
  S("y2-36", "The Button Jar", "🫙", 645, "Nana's button jar held a button from every coat she had ever owned. It rattled when she shook it. Pick one, she said, and I will tell its story. Ruby reached in and chose carefully. She picked a silver one first. That, said Nana, fell off when I danced in the rain. It was my wedding day, she smiled. Ruby loved the story. She picked another button. And another. Each button held a wonderful tale.", "What did each button hold?", [["📖","A story"],["💰","Money"],["🍬","A sweet"]], 0),
  S("y2-37", "Goal of the Season", "⚽", 650, "Ravi never scored a goal. He passed the ball, he ran, he tried his best. But the goal would not come. He kept hoping all season long. On the last match, something amazing happened. The ball bounced off his knee. Then it bounced off his shoulder. Then it hit his head, straight into the goal! The crowd went wild with cheering. The team carried him home on their shoulders. Best knee-shoulder-head goal ever recorded.", "How did Ravi score?", [["🤕","Off knee, shoulder and head"],["🦶","A penalty kick"],["🥅","The keeper missed"]], 0),
  S("y2-38", "The Library Mouse", "🐭", 655, "A mouse lived behind the library shelf. He was always hungry. He nibbled only the boring books. He never touched the exciting ones. The librarian noticed the little holes and frowned. Then she stopped and smiled. She had a clever idea. She used the nibble marks to find dusty books. They were the ones nobody loved. She put exciting new books in their place. The mouse moved on to find more, still hungry as ever.", "Which books did the mouse nibble?", [["🥱","The boring ones"],["🆕","The new ones"],["🐉","Dragon books"]], 0),
  S("y2-39", "The Moon Followed Us Home", "🌕", 660, "Driving home from Granny's, Zain watched the moon out the window. It was big and bright. It followed the car past the quiet farms. It followed over the bridge and around the roundabout. Zain watched it the whole way. It came all the way to his street. It even waited while Dad parked the car. Zain felt happy and sleepy. Goodnight, loyal moon, said Zain softly. See you at Granny's next week, he whispered.", "What did the moon seem to do?", [["🚗","Follow the car"],["😴","Fall asleep"],["🏃","Run away"]], 0),
  S("y2-40", "The Beetle's Umbrella", "🪲", 665, "Rain began just as the beetle crossed the path. The drops came down fast. June wanted to help the little beetle. She picked a dandelion leaf for a roof. She held it over him the whole way. She walked bent like a tiny butler beside him. Step by step they went together. The beetle reached his crack in the wall. He was perfectly dry. June got soaked from head to toe. She decided it was completely worth it.", "What was the beetle's umbrella?", [["🍃","A dandelion leaf"],["☂️","A real umbrella"],["📰","A newspaper"]], 0),
  S("y2-41", "The Recycled Robot", "♻️", 670, "For the school fair, Class Two built a robot. They used boxes and bottle tops. They added an old colander helmet on his head. He looked very grand. He could not walk or talk at all. But he had a special job. His tummy was a posting slot for recycling. The children fed him paper and cans. By home time he was completely full. Class Two cheered with joy. They won the shiny Green Cup that day.", "What was the robot's helmet?", [["🥣","A colander"],["🪣","A bucket"],["🎩","A top hat"]], 0),
  S("y2-42", "First Day Butterflies", "🦋", 675, "Amara's tummy fluttered on the first day at her new school. She felt nervous inside. Butterflies, said Mum, with a gentle smile. Amara wondered if she would make friends. At break, a girl with a gap-tooth grin came over. She asked Amara to skip rope with her. They jumped and laughed together. By lunch the butterflies were gone. Maybe, thought Amara happily, they flew off to find another new kid who needed them most.", "What happened to the butterflies?", [["🕊️","They flew away by lunch"],["😢","They stayed all day"],["🍰","They turned to bees"]], 0),
  S("y2-43", "The Backyard Campout", "⛺", 680, "Dad and Theo pitched the tent three steps from the kitchen door. It felt like a real adventure. They toasted marshmallows over a little fire. They counted the bright stars above. Then they heard a terrible roar! Theo jumped with fright. They peeked outside the tent flap. It was next door's cat, purring against the tent. They both laughed with relief. They let her in to keep warm. Three campers slept till the milkman came.", "What made the terrible roar?", [["🐱","A purring cat"],["🦁","A lion"],["🌩️","Thunder"]], 0),
  S("y2-44", "The Hat Full of Cherries", "🍒", 685, "On the walk home, Grandpa filled his hat with cherries. He picked them from the old tree. The cherries were red and sweet. He shared them all along the way. He gave two to the bus driver. He gave a handful to the twins next door. He gave some to Mrs Pots at the gate. Everyone said thank you kindly. At home, only five cherries were left in his hat. Best hat I own, said Grandpa, smiling.", "What did Grandpa carry cherries in?", [["🎩","His hat"],["🧺","A basket"],["👜","A bag"]], 0),
  S("y2-45", "The Squeaky Gate", "🚪", 690, "The garden gate squeaked like a duck. Eee-aww! It made everyone smile. The real ducks at the pond heard it. They started answering it with loud quacks. The gate quacked, the ducks quacked back. Every visitor laughed at the funny sound. It became the talk of the street. When Dad finally oiled the gate, the squeak stopped. But the garden felt too quiet now. So he let it squeak just a little, for the ducks.", "What did the gate sound like?", [["🦆","A duck"],["🐭","A mouse"],["🎺","A trumpet"]], 0),
  S("y2-46", "Smoothie Experiment", "🥤", 695, "Lena invented a smoothie all by herself. She used banana, berries and spinach. Then she added, secretly, one little sprout. She gave it to Dad to try. Dad drank it all down quickly. Delicious, he said, licking his lips. Then she told him about the sprout. He turned a little green in the face. Then he laughed out loud. He invented his own smoothie with beetroot. Family rule now: one secret vegetable each, every single time.", "What was Lena's secret ingredient?", [["🥬","A sprout"],["🥕","A carrot"],["🧅","An onion"]], 0),
  S("y2-47", "The Helpful Ghost", "👻", 700, "The old house creaked at night, and Tilly blamed a ghost. The noises gave her shivers. But this ghost was helpful and kind. Lost keys appeared back on their hooks. Dropped mittens returned to pockets all by themselves. Tilly was very curious about it. One night Tilly stayed up late to catch it. She hid quietly on the stairs and waited. The ghost was Grandma, tidying in her dressing gown. Boo, said Grandma, kindly, and they hugged.", "Who was the helpful ghost?", [["👵","Grandma"],["👻","A real ghost"],["🐱","The cat"]], 0),
  S("y2-48", "The Number Eight Duck", "🔢", 705, "On pond-feeding day, one duck always arrived last. She paddled in a wobbly figure of eight. The children watched her with delight. They named her Eight because of her funny swimming. They loved her best of all the ducks. When winter came, Eight left with the flock. The pond felt empty without her. The children missed her all season. In spring, a wobbly figure of eight came swirling back across the pond. She remembered them!", "Why was the duck called Eight?", [["🔢","She swam in a figure of eight"],["🥚","She laid eight eggs"],["🕗","She came at eight"]], 0),
  S("y2-49", "The Tallest Sunflower", "🌻", 710, "Three friends planted three sunflower seeds together. They each chose their own way to help. Jo measured hers carefully every day. Ben sang sweet songs to his. Asha just watered hers and waited patiently. The seeds grew slowly through the summer. Green stems climbed up and up. By August, all three towered over the fence. They were exactly the same height! They held their big yellow heads together. They leaned like the best of friends do.", "How tall were the three sunflowers?", [["🤝","All the same"],["1️⃣","Jo's was tallest"],["🎵","Ben's was tallest"]], 0),
  S("y2-50", "The Goodnight Round", "🌙", 715, "Every night the farm said goodnight in turns. It was a cosy bedtime habit. The dog barked once into the dark. The cow mooed low and slow. The hens clucked together softly in their coop. Each animal had its own goodnight sound. Last of all came the smallest one. The smallest kitten gave the smallest mew. It was a tiny, sleepy sound. Only then did the farmer turn off the light. Goodnight, everyone. Goodnight.", "Who said goodnight last?", [["🐱","The smallest kitten"],["🐶","The dog"],["🐔","The hens"]], 0),
];

const YEAR3: Story[] = [
  S("y3-01", "The Midnight Library", "📚", 540, "Mia was sure she heard whispering from her bookshelf at night. One evening she kept her lamp on and watched. At midnight, the storybook characters stretched, yawned, and began tidying their own pages! A tiny knight bowed to her. Keep our secret, he said, and we will always give you the best dreams. Mia promised, and she has slept happily ever since.", "What did the tiny knight ask Mia to do?", [["🤫","Keep the secret"],["⚔️","Fight a dragon"],["📖","Read aloud"]], 0),
  S("y3-02", "The Robot Who Sneezed", "🤖", 550, "Grandpa built a helper robot named Click. Click could sweep, cook, and sing, but whenever it dusted, it sneezed sparks! Achoo! One sneeze toasted the curtains. Grandpa scratched his head, then fitted Click with a tiny vacuum nose. Now Click hoovers the dust before it can tickle, and the only sparks are in his happy robot eyes.", "What made Click sneeze?", [["🌫️","Dust"],["🌶️","Pepper"],["🌸","Flowers"]], 0),
  S("y3-03", "The Penguin Post", "🐧", 560, "Percy the penguin delivered letters across the ice by sliding on his tummy. One stormy day the wind scattered his whole mailbag! Percy did not give up. He chased every envelope over snowdrifts, around seals, under the frozen bridge, until each letter reached its home. The town gave him a medal shaped like a snowflake.", "How did Percy travel across the ice?", [["🛷","Sliding on his tummy"],["🚲","Riding a bike"],["🛶","Paddling a canoe"]], 0),
  S("y3-04", "The Upside-Down Garden", "🌷", 570, "Nia's grandma grew flowers from hanging baskets, so the garden seemed to bloom from the sky. Bees held meetings under the floating roses, and butterflies used the petunias as swings. When the summer fair came, the judges had never seen anything like it. Grandma won first prize, and Nia won something better: the seeds for next year.", "Where did Grandma's flowers grow?", [["🧺","In hanging baskets"],["🛁","In a bathtub"],["👢","In old boots"]], 0),
  S("y3-05", "The Echo in the Cave", "🦇", 580, "On a school trip, Leo discovered that the cave answered him. Hello! he called, and Hello-lo-lo rolled back. He tried a riddle, and the echo finished it. The guide explained how sound bounces off rock walls, but Leo grinned all the way home. Science or not, he had spent the morning talking with a mountain.", "What did Leo talk with?", [["⛰️","The echo in the cave"],["🦜","A parrot"],["📻","A radio"]], 0),
  S("y3-06", "The Baker's Mistake", "🥐", 590, "Baker Ben grabbed the wrong jar and put chilli powder in the cinnamon buns. The first customer turned red and gulped a whole jug of milk! Ben wanted to hide, but the customer laughed and asked for another. Soon the whole town queued for fire buns. Sometimes, Ben learned, a mistake is just a recipe nobody has tried yet.", "What went into the buns by mistake?", [["🌶️","Chilli powder"],["🧂","Salt"],["🧄","Garlic"]], 0),
  S("y3-07", "The Littlest Lighthouse", "🗼", 600, "The old lighthouse was too short to be seen over the new tall buildings, and the keeper worried ships would be lost. The town's children had an idea: every evening they carried mirrors to the rooftops and bounced the small light high across the bay. The fishing boats came home safely, guided by a lighthouse made taller by helping hands.", "How did the children help?", [["🪞","They bounced light with mirrors"],["🧱","They built it taller"],["🔥","They lit a bonfire"]], 0),
  S("y3-08", "The Tortoise Taxi", "🐢", 610, "When the ants' picnic ground flooded, Tully the tortoise offered rides on her shell. Back and forth she paddled, ferrying crumbs, teapots, and three hundred passengers to dry land. It took all afternoon, and the ants repaid her with a garden of her favourite dandelions planted in a ring around her pond.", "What did the ants give Tully?", [["🌼","A dandelion garden"],["🍰","A cake"],["👑","A crown"]], 0),
  S("y3-09", "The Borrowed Bark", "🐕", 615, "Luna the dog lost her bark after a long day of guarding sheep. The vet said, rest your voice. So the farm goose volunteered. For one whole week, whenever a stranger came, the goose honked and Luna mimed along. Strangers were twice as confused and left twice as fast. Best guard team in the valley, said the farmer.", "Who covered for Luna's lost bark?", [["🪿","The goose"],["🐱","The cat"],["🐴","The horse"]], 0),
  S("y3-10", "The Puddle Map", "🗺️", 620, "After rain, Tia noticed the puddles on her street always made the same shapes. The long one by the postbox, the round twins outside the bakery. She drew them all in her notebook and named them like lakes. When the council fixed the road, Tia kept her map. Explorers, she said, remember the lands that vanish.", "What did Tia map?", [["💧","The street's puddles"],["⭐","The stars"],["🏠","The houses"]], 0),
  S("y3-11", "Grandfather Clock's Holiday", "🕰️", 625, "The grandfather clock had ticked in the hall for ninety years. When the repair man took it away for two weeks, the house felt wrong. Meals ran late. Bedtime wandered. Even the cat missed her four o'clock sunbeam. When the clock returned, polished and proud, the whole family stood in the hall just to hear it strike.", "How did the house feel without the clock?", [["😕","Wrong and muddled"],["🎉","More fun"],["😴","Sleepier"]], 0),
  S("y3-12", "The Kindness Coupon", "🎟️", 630, "For Mother's Day, Eli had no money at all, so he made a little book of coupons. He wrote one free washing-up, one extra-long hug, and one quiet morning, then tied them with string. His mum opened the book and smiled. She used the extra-long hug coupon immediately, squeezing him tight, and then she photocopied the rest to use again. That is cheating, laughed Eli, shaking his head. That, said Mum, with a wink, is economics.", "Which coupon did Mum use first?", [["🤗","The extra-long hug"],["🍽️","The washing-up"],["🤫","The quiet morning"]], 0),
  S("y3-13", "The Beach in a Jar", "🏖️", 635, "Holidays ended, but Noor was not ready to leave the sea. She filled a jar: sand at the bottom, three shells, one smooth blue stone, and air that smelled of salt. All winter the jar sat on her desk. On grey days she opened the lid, closed her eyes, and went back for one breath of summer.", "What did Noor keep in her jar?", [["🐚","The beach"],["🍬","Sweets"],["🐠","A fish"]], 0),
  S("y3-14", "The Wrong Trumpet", "🎺", 640, "Jonas asked for a trumpet for his birthday. His aunt, who heard badly on the phone, sent a crumpet. The family laughed until tea time, then put a candle in the crumpet and sang. Next morning, a parcel arrived: a real trumpet, with a note. Practise quietly. PS: eat the first present.", "What arrived first by mistake?", [["🫓","A crumpet"],["🥁","A drum"],["🎻","A violin"]], 0),
  S("y3-15", "The Stone Soup Picnic", "🍲", 645, "Nobody in the street had enough for a feast, so old Mr Han set a pot boiling with just a stone in it. Curious neighbours drifted over. One added carrots, one added noodles, one added dumplings. By sunset, forty people shared the richest soup ever made from one shiny stone.", "How did the soup get rich?", [["🥕","Everyone added something"],["🪨","The stone melted"],["🛒","Mr Han bought it all"]], 0),
  S("y3-16", "The Swap Shop", "🔁", 650, "The school held a swap shop: bring one toy, take one home. Theo brought a robot with a missing arm and worried no one would want it. A small girl gasped, just like mine at home, they can be twins! Theo went home with a kite and the warm feeling of a perfect trade.", "What did Theo bring to swap?", [["🤖","A one-armed robot"],["🪁","A kite"],["🧸","A teddy"]], 0),
  S("y3-17", "The Night the Stars Fell", "🌠", 655, "Late one night, Dad woke Maya at midnight with hot chocolate and warm blankets. They tiptoed outside and climbed the dark hill together. On the hill, they lay back and counted shooting stars streaking across the sky: seven, twelve, twenty! Maya wished on the very first three, then she just watched in wonder. Some things, Dad said softly, are better watched than wished on. The hot chocolate went cold in their cups. Nobody minded at all that night.", "What did Dad bring to the hill?", [["☕","Hot chocolate and blankets"],["🔭","A telescope"],["🎪","A tent"]], 0),
  S("y3-18", "The Borrowing Crow", "🐦‍⬛", 660, "A crow kept taking shiny things from the garden: a teaspoon, a marble, Mum's ring! Ada followed it to a hole in the oak. Inside sat a glittering little museum. She took back the ring and left a coin as a swap. The crow inspected it, nodded once, and they were even.", "What did Ada leave as a swap?", [["🪙","A coin"],["💍","A ring"],["🥄","A spoon"]], 0),
  S("y3-19", "Mr Pickle's Hundred Hats", "🎩", 665, "Mr Pickle owned one hundred hats but always wore the brown one. When the wind stole it into the river, the whole street offered him their hats. He tried a chef's hat, a crown, a sombrero. Next morning, a soggy brown hat sat drying on his gate, returned by the river. Old friends, he said, find their way home.", "Which hat did Mr Pickle always wear?", [["🟤","The brown one"],["👑","The crown"],["👨‍🍳","The chef's hat"]], 0),
  S("y3-20", "The Quiet Race", "🤫", 670, "Sports day had a new event: the quiet race. Carry a spoon egg, no talking, no giggling. The hall was silent until Marco's egg wobbled. A snort escaped. Then the whole hall exploded with laughter, eggs everywhere. The teachers gave everyone first prize for trying, and the quiet race was never quiet again.", "What did racers carry?", [["🥚","An egg on a spoon"],["📚","Books"],["💧","A cup of water"]], 0),
  S("y3-21", "The Map of Smells", "👃", 675, "Blindfolded for a game with friends, Ines found that she knew her whole street by nose alone. Warm bread smell told her the bakery corner was near. Sharp paint smell meant Mr Lim's shed. Sweet rose smell drifted from number twelve. Carefully, she drew a special map with no streets on it at all, just smells one after another. Her little brother held the map and followed it perfectly, sniffing his way along until he reached the sweet shop.", "How did Ines map her street?", [["👃","By smells"],["👀","By colours"],["👂","By sounds"]], 0),
  S("y3-22", "The Penalty Save", "🧤", 680, "Goalkeeper Ruby faced the last penalty of the final. She remembered her coach: watch the eyes, not the ball. The striker glanced left. Ruby dived left. The ball thumped into her gloves! Her team buried her in a hug so big the referee had to dig her out to give her the trophy.", "What did Ruby watch?", [["👀","The striker's eyes"],["⚽","The ball"],["🥅","The goal"]], 0),
  S("y3-23", "The Lost Recipe", "📜", 685, "Grandma's famous biscuit recipe blew out the window and into the world. She tried baking from memory: too flat, too hard, too sad. Then little Sol remembered licking the bowl and the secret pinch of cinnamon. Together they rebuilt the recipe, taste by taste, and wrote two copies this time.", "Who remembered the secret ingredient?", [["👦","Little Sol"],["👵","Grandma"],["📖","The recipe book"]], 0),
  S("y3-24", "The Theatre of Socks", "🧦", 690, "Stuck indoors with chickenpox, Bram turned his hands into actors. Sock dragons, sock pirates, a sock queen with a paper crown. Mum was the audience, then the doctor, then the postman through the window. By the time the spots faded, Bram's Theatre of Socks had performed eleven shows and taken four bows.", "Why was Bram stuck indoors?", [["🔴","Chickenpox"],["🌧️","Rain"],["👟","No shoes"]], 0),
  S("y3-25", "The Whistling Postman", "😗", 695, "The old postman whistled a different tune for every single street he visited. Hearing his cheerful song through the window, you knew the post was only three doors away. Everyone loved his music. When he finally retired, he kindly taught the new postwoman every street's special tune so the songs would carry on. The very first morning she walked the round and whistled, fourteen front doors swung open at once, all along the road, just so people could say hello.", "How did people know the post was near?", [["🎵","By the whistled tune"],["🔔","By a bell"],["🐶","By dogs barking"]], 0),
  S("y3-26", "The Iceberg Lettuce", "🥬", 700, "Dad joked that iceberg lettuce came from real icebergs. Mina believed him for exactly one day, drawing penguins farming green icebergs. At school her teacher explained, gently, while trying not to laugh. Mina came home and drew one more picture: Dad on an iceberg, planted up to his knees in lettuce. Fair is fair.", "What did Mina draw last?", [["🧊","Dad planted in lettuce"],["🐧","Penguin farmers"],["🥬","A lettuce castle"]], 0),
  S("y3-27", "The Bell That Rang Twice", "🔔", 705, "At Oakdale School, the bell rang once for lessons and twice for emergencies. Everyone knew the rule well. One sunny Tuesday morning, the bell rang twice, so the whole school filed out quickly and quietly. The emergency? A fluffy duck family was waddling across the playground towards the pond. Three hundred excited children watched in respectful silence as the ducklings hurried by in a wobbly line. Best emergency ever, the head teacher admitted afterwards, laughing and shaking her head with delight.", "What was the emergency?", [["🦆","Ducks crossing the playground"],["🔥","A fire"],["❄️","Snow"]], 0),
  S("y3-28", "The Grandpa Exchange", "🔄", 710, "Lily's grandpa told the most brilliant, exciting stories, but he always burned the toast. Mo's grandpa baked perfectly golden bread, yet he told the very same story every single day. So, on Sundays, the two families happily swapped houses. They had stories at Mo's place and warm baking at Lily's. The children loved it. By summer, both clever grandpas had quietly learned the other's trick, and Sundays slowly became a friendly competition that nobody really wanted to win.", "What happened on Sundays?", [["🔄","The grandpas swapped houses"],["🛌","Everyone slept in"],["⚽","They played football"]], 0),
  S("y3-29", "The Paper Aeroplane Champion", "✈️", 715, "Suri folded paper planes that flew like sleepy moths, while her rival Dev built sleek darts. At the contest, Dev's dart shot straight into a wall. Suri's moth wobbled, caught a warm breeze from the radiator, and drifted the whole length of the gym. Slow, she said, collecting her medal, is a kind of clever.", "How did Suri's plane win?", [["♨️","It drifted on warm air"],["💨","It was fastest"],["🧲","It used magnets"]], 0),
  S("y3-30", "Operation Birthday Cake", "🕵️", 720, "Mum's surprise cake had to be hidden for two days. The fridge was too obvious; the oven too risky. The twins finally hid it in the doll's house, guarded by every toy soldier they owned. Mum walked past it forty times. At the party she said, I searched everywhere! Not everywhere, said the twins, saluting.", "Where was the cake hidden?", [["🏠","In the doll's house"],["🧊","In the fridge"],["🛏️","Under a bed"]], 0),
  S("y3-31", "The Tide Pool Hotel", "🦀", 725, "Every low tide, the rock pool filled with guests: a hermit crab, two anemones, a starfish that never checked out. Kai appointed himself hotel manager, refreshing the seaweed beds daily. When the big tide came and swept the pool clean, he just smiled. Checkout day, he said. New guests at six.", "What did Kai call the big tide?", [["🛎️","Checkout day"],["🌊","Disaster day"],["🎉","Party day"]], 0),
  S("y3-32", "The Shoes That Squeaked Songs", "🎵", 730, "Pia's shiny new shoes squeaked loudly on the polished school floor. Squeak-squeak, squeak-squeak, perfectly in rhythm with every step! By Friday, she could squeak a whole tune as she walked all the way to assembly. Everyone giggled at the funny sound. The music teacher, instead of frowning crossly, listened carefully and wrote the squeaks down on her paper. The school song now contains, completely officially, two whole bars for squeaky shoes, and Pia feels very proud indeed.", "What did the music teacher do?", [["🎼","Wrote the squeaks into the song"],["😠","Banned the shoes"],["🧴","Oiled the floor"]], 0),
  S("y3-33", "The Great Marble Flood", "🔮", 735, "Oscar's marble jar, balanced on the top shelf, finally tipped. Five hundred marbles thundered down the stairs like a glass waterfall! The family spent all evening finding them: in plant pots, slippers, the sugar bowl. The last marble turned up in spring, inside a welly, and everyone cheered like it was a lost explorer.", "Where was the last marble found?", [["🥾","Inside a welly"],["🍬","In the sugar"],["🌱","In a plant pot"]], 0),
  S("y3-34", "The Lighthouse Cat", "🐈", 740, "Smudge the cat climbed the lighthouse stairs every evening to sit beside the great lamp. Sailors began to look for her silhouette, a small ear-shaped bump in the beam. When she had kittens, four tiny bumps joined the light, and the fishermen swore the harbour had never felt so safe.", "What did sailors look for in the beam?", [["🐱","The cat's silhouette"],["🦅","A seagull"],["🚩","A flag"]], 0),
  S("y3-35", "The Backwards Bicycle", "🚲", 745, "At the fair, a prize waited for anyone who could ride the trick bicycle: steer left, it goes right! Strong men wobbled. Show-offs crashed into hay. Then quiet Ana, who had practised all year on her brother's broken bike, sailed through the course backwards-brained and calm, and pedalled off with the trophy.", "Why could Ana ride the trick bike?", [["🔧","She practised on a broken bike"],["💪","She was strongest"],["🍀","Pure luck"]], 0),
  S("y3-36", "The Sandwich Swap Club", "🥪", 750, "Every lunchtime, Amir's mum packed soft dates and flatbread; Hana's dad packed neat rice balls; Lou's nan packed crusty cheese rolls. One day, the three friends had a bright idea and cut everything carefully into thirds to share. Three lunches suddenly became nine little tastes spread across the table. It was delicious. The lunch-sharing club grew bigger and bigger until the whole table ate like happy world travellers, trying new flavours every day, passports not required at all.", "What did the club share?", [["🍱","Their lunches"],["📚","Homework"],["⚽","Stickers"]], 0),
  S("y3-37", "The Dragon in the Radiator", "🐉", 755, "The radiator gurgled and clanked all winter. There is a small dragon in there, Dad said, warming us. Posy left it a saucer of water and a biscuit each night. Each morning, the biscuit was gone. Years later she caught Dad sneaking the biscuit, and he caught her smiling. The dragon, they agreed, must never find out.", "What did Posy leave for the dragon?", [["🍪","Water and a biscuit"],["🥩","Meat"],["🧦","A sock"]], 0),
  S("y3-38", "The Snow Library", "📖", 760, "Snow closed the village school, but Miss Reed opened her cottage instead. Children arrived on sledges with books under their coats. They read by the fire, drank cocoa, and built a snow reader outside, complete with icicle bookmark. Best school day ever, they agreed, and not one lesson was missed that mattered.", "Where did the children read?", [["🔥","By Miss Reed's fire"],["🏫","At school"],["⛄","In an igloo"]], 0),
  S("y3-39", "The Pocket Full of Seeds", "🌰", 765, "Grandad's old coat pockets always held a handful of seeds. On their long walks together, he quietly flicked them into hedges and forgotten waste corners, saying nothing at all about it. Ada often wondered why. Years and years later, she walked those very same paths under sweet apple blossom and tall, nodding wild sunflowers. Smiling, she filled her own pockets with seeds that day. The walk, Grandad had always called it, that takes a full thirty years to finish.", "What did Grandad keep in his pockets?", [["🌱","Seeds"],["🍬","Sweets"],["🪙","Coins"]], 0),
  S("y3-40", "The Choir of Frogs", "🐸", 770, "The pond frogs croaked loudly all night long before rain, like a weather forecast that nobody had even asked for. After a while, the whole town began to notice something strange: the frogs were never, ever wrong about the weather. The radio weatherman, who often got it wrong himself, came down to visit the pond with his microphone. Now the morning forecast ends, completely officially, with the frog report, and the listeners trust it more than ever.", "Why did the town trust the frogs?", [["✅","They were never wrong"],["🎵","They sang sweetly"],["📺","They were famous"]], 0),
  S("y3-41", "The Hundred-Year Sandcastle", "🏰", 775, "The sign by the dunes said a wizard once built a sandcastle that lasted one hundred years. Rubbish, said Tom, building his own. That night he dreamed of turrets in moonlight. Next morning, his castle alone stood untouched by the tide, one shell brighter on its gate. Tom said nothing. Some rubbish is worth believing.", "What was different about Tom's castle?", [["🌊","The tide left it standing"],["💎","It turned to stone"],["🚩","It grew a flag"]], 0),
  S("y3-42", "The Reading Dog", "🦮", 780, "Shy young readers at the library could book ten quiet minutes with Biscuit, a calm golden retriever who listened to stories without ever once correcting anyone. He simply wagged his tail. Children who only whispered nervously to their teachers somehow read loudly and boldly to Biscuit. He sat so patiently. He had just one rule, enforced very gently with a soft paw: stories with tasty sausages in them had to be read aloud twice, from start to finish.", "What was Biscuit's one rule?", [["🌭","Sausage stories twice"],["🤫","Whisper only"],["📕","No scary books"]], 0),
  S("y3-43", "The Upside-Down Rainbow", "🌈", 785, "After the cold snap, a rainbow appeared upside down, a huge smile in the sky. The science teacher explained about ice crystals; the art teacher handed out paper. Aria drew the sky smiling and added the sun winking. Hers went on the wall, label and all: Rare sky, in a good mood.", "What did the upside-down rainbow look like?", [["😊","A smile in the sky"],["🌉","A bridge"],["🍌","A banana"]], 0),
  S("y3-44", "The Slow Cooker", "🍯", 790, "Aunt Rosa's stew cooked from breakfast to dinner, filling the house with impatience. Theo checked it hourly. Not yet, said Aunt Rosa, good things travel slowly. When at last the lid came off, the whole street seemed to be at the table. Theo counted chairs and understood: slow does not just feed you. It gathers.", "What did the slow stew do?", [["🪑","Gathered the whole street"],["💨","Cooked too fast"],["🧊","Went cold"]], 0),
  S("y3-45", "The Borrowed Moonlight", "🌙", 795, "Power cut! The whole house went suddenly dark, and the torch batteries were completely flat. But the bright full moon poured down through the skylight like cool silver milk, filling every room. The happy family played cards in the moonlight, told funny stories in the moonlight, and even brushed their teeth by moonlight. It felt magical. When the electric bulbs finally blinked back on, everyone groaned loudly and quickly turned half the lights off again.", "What lit the house in the power cut?", [["🌕","Moonlight"],["🕯️","Candles"],["🔦","A torch"]], 0),
  S("y3-46", "The Ant Bridge", "🐜", 800, "Rain split the garden path, and the ants' trail broke at the crack. Within an hour, the ants had linked legs to build a living bridge, traffic marching calmly across their backs. Mara watched, amazed, then laid a twig beside them to help. The ants inspected it, approved it, and made it a two-lane road.", "What did the ants first build the bridge from?", [["🐜","Their own bodies"],["🪵","Twigs"],["🍃","Leaves"]], 0),
  S("y3-47", "The Forgetful Magician", "🎩", 805, "The magician at Ben's party forgot every trick's ending. Cards vanished and stayed vanished; the rabbit refused to reappear. Disaster? The children loved it. They spent the party finding doves in curtains and coins behind their own ears. Best treasure hunt ever, and the rabbit turned up asleep in the cake box.", "Where was the rabbit found?", [["🎂","Asleep in the cake box"],["🎩","In the hat"],["🛋️","Under the sofa"]], 0),
  S("y3-48", "The Window Seat", "🚌", 810, "On the long, bumpy coach trip, everyone wanted the comfy window seat. Nia and Sol cleverly struck a fair deal: she got all the mountains, and he got all the towns. They swapped seats happily at every single stop, narrating the view like proper tour guides. People started listening. Somewhere past the third sleepy town, the kids sitting in the aisle were cheerfully paying Nia and Sol in crisps just to hear more of their funny commentary.", "How did Nia and Sol share the seat?", [["🔄","Swapped at each stop"],["✊","Rock paper scissors"],["😴","One slept"]], 0),
  S("y3-49", "The Hat Parade", "👒", 815, "School announced a hat parade: make it yourself, anything goes. Mira built a working windmill hat. Joss balanced a goldfish-bowl hat (no fish, by order of Mum). Pravin came as a postbox, head and all. The judges gave first prize to tiny Eve, whose hat was simply a nest, occupied that morning by a real, surprised sparrow.", "Whose hat won the parade?", [["🪺","Eve's nest hat"],["🌬️","Mira's windmill"],["📮","Pravin's postbox"]], 0),
  S("y3-50", "The Last Conker", "🌰", 820, "Frost came early, and one last conker clung to the bare tree. The whole class watched it through October, a small brown stubborn flag. The day it finally fell, Mr Aziz caught it, polished it, and pinned a label: To spring. They planted it by the gate, and it is a tree now, taller than the school sign.", "What happened to the last conker?", [["🌳","It was planted and grew"],["🎮","It was used in a game"],["🐿️","A squirrel took it"]], 0),
];

const YEAR4: Story[] = [
  S("y4-01", "The Map in the Attic", "🗺️", 640, "While helping clear the attic, Zara found a map of her own town, but drawn a hundred years ago. The supermarket was an orchard; the bus stop was a bandstand. She followed the old paths after school, and at the spot marked with a tiny bell she dug up a rusted tin. Inside lay letters from children long grown, asking whoever found them to write back. Zara is still writing her reply, and it keeps getting longer.", "What did Zara dig up?", [["📦","A tin of letters"],["💎","A box of jewels"],["🔔","A church bell"]], 0),
  S("y4-02", "The Kitchen Orchestra", "🥁", 650, "Rehearsal rooms cost money, so Marcus practised drums on saucepans, and his sister played flute along with the kettle's whistle. Their neighbour complained, until the night of the blackout, when the whole street gathered in their garden. The kitchen orchestra played by candlelight, neighbours sang, and the complaint was officially withdrawn with a plate of biscuits.", "When did the neighbours change their minds?", [["🕯️","During the blackout"],["🎄","At Christmas"],["☀️","In summer"]], 0),
  S("y4-03", "Letters to a Glacier", "🧊", 660, "For a class project, Tom wrote a letter to a glacier, joking that it should write back. His teacher posted it to a research station in Iceland. Months later an envelope arrived containing a photograph of his letter frozen a metre deep in blue ice, and a note from a scientist: your letter will travel inside the glacier for fifty years. Write to us in 2076 and we will tell you where it came out.", "Where was Tom's letter placed?", [["🧊","Inside a glacier"],["🌋","Inside a volcano"],["🌊","In the sea"]], 0),
  S("y4-04", "The Fox Who Read the News", "📰", 670, "Every morning the fox stole one newspaper from the village shop, only one, and always the same kind. Curious, the shopkeeper followed the paw prints to a hollow oak. Inside, the fox had lined a nest for her cubs with crosswords and comics. The shopkeeper smiled, and from then on left yesterday's unsold papers at the foot of the tree.", "What did the fox use the newspapers for?", [["🛏️","Lining her cubs' nest"],["📖","Reading the sport"],["🔥","Starting a fire"]], 0),
  S("y4-05", "The Singing Postbox", "📮", 680, "The postbox on Harbour Lane hummed sea shanties, and nobody knew why. Letters posted there arrived smelling of salt. Old sailors tipped their caps to it. When engineers finally opened it, they found nothing but a curl of wind trapped since the great storm of 1932, or so the harbour master says, with a wink that suggests he oils its hinges himself.", "What did letters from the postbox smell of?", [["🌊","Salt"],["🌹","Roses"],["☕","Coffee"]], 0),
  S("y4-06", "The Comet Watchers", "☄️", 690, "The comet would pass only once in their lifetimes, and clouds covered the whole valley. Most people went to bed disappointed. But Asha and her grandfather drove up the mountain road, above the weather, and watched the sky split open with silver light. The photograph they took hangs in the school hall, captioned: the sky rewards those who climb.", "Why did Asha drive up the mountain?", [["☁️","To get above the clouds"],["⛽","To buy fuel"],["🦌","To see deer"]], 0),
  S("y4-07", "The Bridge of Buttons", "🧵", 700, "When the footbridge rotted away, the village had no money for steel. The tailor suggested something strange: a rope bridge woven through thousands of donated buttons, each one threaded by a different villager. It took a winter of evenings around the fire. Now visitors come from far away to cross it, and every villager can point to a button and say, that one is mine.", "What was woven into the bridge?", [["🔘","Buttons"],["🐚","Seashells"],["🪙","Coins"]], 0),
  S("y4-08", "The Whale's Library", "🐋", 710, "Marine scientists discovered that the old whale sang differently near the sunken cargo ship. Diving down, they found the hold full of waterlogged books, their pages long dissolved. Yet the whale returned each season to sing where the stories had been. Perhaps, wrote the youngest scientist in her log, some readers never need the words at all.", "Where did the whale sing differently?", [["🚢","Near the sunken ship"],["🏝️","Near the island"],["🧊","Near the ice"]], 0),
  S("y4-09", "The Hundred Umbrella Day", "☂️", 715, "The forecast promised the storm of the decade, and the town prepared: a hundred umbrellas bristling down the high street like a parade of beetles. The storm, embarrassed, delivered four polite drops and left. Nobody folded up. They walked the dry street under their useless umbrellas, laughing, and the café sold out of everything by noon.", "How much rain actually fell?", [["💧","Four drops"],["🌊","A flood"],["❄️","It snowed"]], 0),
  S("y4-10", "The Inventor of Quiet", "🤐", 720, "Rohan's little sister was loud. Loud songs, loud questions, loud everything. So he invented Quiet Hour with official tickets, a sand timer, and a prize for the stillest person. His sister won every single day. It took Rohan a month to realise she was cheating: she napped. He let the record stand. Inventors, he reasoned, should reward genius.", "How did the sister win Quiet Hour?", [["😴","She napped"],["🤫","She whispered"],["🚪","She left the room"]], 0),
  S("y4-11", "The Library of Borrowed Things", "🔧", 725, "The new library lent more than books: drills, cake tins, telescopes, a ukulele. Mr Okon borrowed the telescope and returned it with a star map he had drawn. Someone borrowed the cake tin and returned it with a cake. The librarian made a new rule, the first of its kind: returns may be improved.", "What was the library's new rule?", [["✨","Returns may be improved"],["⏰","Return in one week"],["🚫","No food allowed"]], 0),
  S("y4-12", "The Wrong Bus Adventure", "🚍", 730, "Half asleep, Priya boarded the 42 instead of the 24 and rode it to the end of the line, a harbour she never knew her town owned. Fishermen mended nets; a seal barked at gulls. She caught the right bus home an hour late with a pocket of shells and a plan: once a month, on purpose, the wrong bus.", "What did Priya find at the end of the line?", [["⚓","A harbour"],["🏰","A castle"],["🎡","A funfair"]], 0),
  S("y4-13", "The Beekeeper's Telephone", "📞", 735, "Old Marta kept an antique telephone by her hives, unconnected to anything. Visitors saw her lift the receiver and murmur. Telling the bees the news, she explained: a wedding, a good harvest, rain coming. Scientists smiled politely. But her honey won gold every year, and the judges always asked what her secret was. Good conversation, said Marta.", "What was Marta's honey secret?", [["🗣️","Talking to the bees"],["🌸","Special flowers"],["🍯","A secret recipe"]], 0),
  S("y4-14", "The Glow-in-the-Dark Garden", "🌌", 740, "For her science project, Wren planted white flowers that caught the moonlight: evening primrose, night phlox, silver thyme. By August the back garden glowed like spilled starlight, and moths arrived like tiny ghosts. Her write-up earned an A. Her garden earned something better: neighbours leaning on the fence at midnight, whispering wow.", "When did Wren's garden look best?", [["🌙","At night"],["🌅","At dawn"],["🕛","At noon"]], 0),
  S("y4-15", "The Great Pancake Relay", "🥞", 745, "The village pancake race had a twist: teams of four, one pan, flip at every corner. Gran anchored their team, having flipped pancakes since before the war memorial was built. At the final corner their pancake spun high, somersaulted twice, and landed perfectly. The trophy went on the mantel; the pancake, dusty but heroic, went to the dog.", "Who got the racing pancake afterwards?", [["🐶","The dog"],["👵","Gran"],["🏆","The judges"]], 0),
  S("y4-16", "The Boy Who Mapped Thunder", "⛈️", 750, "Eli feared storms until his uncle taught him the counting trick: seconds between flash and rumble, divided by three, gives kilometres. Fear became arithmetic. Soon he charted each storm's march across the valley like a general. The night the big one came, his family gathered around his map instead of jumping at every boom, and he narrated the storm right out of town.", "What did counting seconds tell Eli?", [["📏","How far the storm was"],["⏰","When rain would stop"],["🌡️","How cold it was"]], 0),
  S("y4-17", "The Second-Hand Telescope", "🔭", 755, "The telescope from the charity shop came with a handwritten label inside the case: Saturn looks best in October, ask for Edna's bench. They found the bench on the hill, dedicated to Edna who watched the skies here. All October they took turns at the eyepiece on her bench. Saturn, as promised, was magnificent, and they left the label for the next owner.", "What did the label recommend?", [["🪐","Saturn in October"],["🌕","The moon in May"],["☀️","Sunrises"]], 0),
  S("y4-18", "The Town That Swapped Houses", "🏘️", 760, "For one weekend a year, the tiny town of Marle swapped homes by lottery. The baker slept in the lighthouse; the teacher minded the farm. They returned home with new respect and excellent gossip. Maya's family drew the houseboat, and she woke to ducks tapping the porthole like tiny impatient milkmen. Best lottery ever, she declared.", "Which home did Maya's family draw?", [["🛥️","The houseboat"],["🗼","The lighthouse"],["🚜","The farm"]], 0),
  S("y4-19", "The Chess Set of Two Villages", "♟️", 765, "Carved a century ago, the chess set had white pieces made in one village and black in the other, and the giant board was painted on the bridge between them. Every midsummer the villages played one game, walking pieces across by hand. Nobody remembers the score. Everybody remembers that the bridge has never once needed an army.", "Where was the giant chessboard?", [["🌉","On the bridge"],["⛪","In the church"],["🏞️","In a field"]], 0),
  S("y4-20", "The Sandwich That Travelled", "🥪", 770, "Dad's forgotten sandwich rode his briefcase to three meetings, a train, and a conference in another city. It returned home untouched, slightly famous, having appeared in the background of a television interview. The family framed a screenshot. The sandwich itself, by unanimous vote and with full honours, went to the compost heap.", "Where did the sandwich finally go?", [["🌱","The compost heap"],["📺","A museum"],["🍽️","Dad ate it"]], 0),
  S("y4-21", "The Night Bakery", "🥖", 775, "Insomniac Mr Bram turned his sleepless three a.m. hours into bread. The smell drifted down the street like a kind rumour, and one by one the other wakeful ones found his lit window: the nurse off shift, the new mother, the old soldier. He never charged the night visitors. Bread, he said, costs flour. Company at three a.m. is priceless.", "What did Mr Bram never charge for?", [["🌙","Night visitors' bread"],["🎂","Birthday cakes"],["☕","Coffee"]], 0),
  S("y4-22", "The School of Small Rivers", "🏞️", 780, "Their stream began somewhere, and Class Four meant to find it. With wellies and a packed-lunch permission slip, they followed it upstream past three farms, under a motorway, through a wood full of wood pigeons, to a spring no bigger than a dinner plate, bubbling out of moss. Our river, wrote Femi in the class log, starts the size of soup.", "How big was the stream's source?", [["🍽️","The size of a dinner plate"],["🏊","The size of a pool"],["🚪","The size of a door"]], 0),
  S("y4-23", "The Violin Made of Rain", "🎻", 785, "The old gutter outside the music room dripped in three places, each a different note. While others heard a broken pipe, Miss Caro heard a beat. She tuned her violin to the drips and composed Rain Trio for Gutter and Strings. At the spring concert the audience sat beneath umbrellas indoors, by request, and the gutter received its own bow.", "What did Miss Caro tune her violin to?", [["💧","The dripping gutter"],["🎹","A piano"],["🔔","Church bells"]], 0),
  S("y4-24", "The Memory Shop", "🎁", 790, "The sign read: We buy nothing, we sell nothing, bring a memory. Inside, old Mrs Keel recorded anyone who would talk: first bicycles, lost dogs found, the day the river froze. Children listened at the booths to voices older than their grandparents. Otto told his story of catching the biggest perch ever seen, which grew, as recorded fish do, a little every year.", "What did people bring to the shop?", [["🧠","Memories"],["🪙","Coins"],["📚","Old books"]], 0),
  S("y4-25", "The Kite Doctor", "🪁", 795, "After every windy weekend, broken kites piled up at lost property. Caretaker Joe started a Monday clinic: splints for spars, patches for tears, new tails from old ties. He pinned each repaired kite to the noticeboard with a recovery report. Patient flew again at 3pm, it might say. Gusty conditions. Made a full recovery. Owner cried. So did caretaker.", "What did Joe pin to the noticeboard?", [["📋","Kite recovery reports"],["💰","Repair bills"],["📷","Photos of clouds"]], 0),
  S("y4-26", "The Hundred-Step Garden", "🌿", 800, "The steep lane to Ivy's house had exactly one hundred steps, and every household tended the five steps outside their door. Marigolds on twenty to twenty-five, mint at sixty, a tiny bench and free lemonade at ninety. Climbing it was less like a staircase, visitors said, and more like reading a very kind story uphill.", "How was the staircase gardened?", [["🪜","Five steps per household"],["🏛️","By the council"],["🤖","By robots"]], 0),
  S("y4-27", "The Weathervane Rooster", "🐓", 805, "The iron rooster on the town hall had pointed wrong for forty years, ever since a storm bent his tail. The town liked him crooked: when he said north, you brought an umbrella for the east wind. The day a well-meaning repairman straightened him, half the town got soaked, and a petition went round by tea time. He was ceremonially re-bent that Friday.", "Why did the town re-bend the rooster?", [["🌧️","His wrongness predicted weather"],["🎨","It looked prettier"],["💰","Repairs were cheap"]], 0),
  S("y4-28", "The Floating Cinema", "🎬", 810, "Once a summer, the harbour town strung a sail between two masts and projected films across the water. Families watched from rowboats, sharing popcorn boat to boat. The year the heron landed on the sail mid-film, casting a vast shadow puppet across the pirate ship scene, the audience applauded so hard that three rowboats nearly capsized.", "What was the cinema screen?", [["⛵","A sail between masts"],["🧱","A warehouse wall"],["📺","A giant TV"]], 0),
  S("y4-29", "The Apology Cake", "🍰", 815, "When Dev accidentally broke Mr Singh's window with a cricket ball, his nana refused to let him just say sorry. Sorry is the icing, she said, kindness is the cake. They baked all afternoon. Dev delivered it, confessed, and offered Saturday mornings for garden work. By October, Mr Singh was teaching him spin bowling, far from any windows.", "What did Nana say sorry was?", [["🧁","Just the icing"],["🎂","The whole cake"],["🍞","The flour"]], 0),
  S("y4-30", "The Star Jar Promise", "⭐", 820, "Every time someone in 4B helped without being asked, a paper star went in the jar. Full jar meant a class camp-out in the gym. Stars came fast at first, slower in winter, then something changed: helping became a habit nobody noticed. The jar filled twice over. The night of the camp-out, Miss Lane tipped both jars into the air and called it a constellation.", "What did a full jar earn the class?", [["⛺","A gym camp-out"],["🍕","A pizza party"],["📺","A film day"]], 0),
  S("y4-31", "The Boat Made of Doors", "🚪", 825, "After the flood, the carpenter built a small ferry from the village's ruined doors, every panel a different colour, every knocker still attached. Crossing the river, passengers liked to knock on the red door for luck. Years later, when a proper bridge came, the door-boat retired to the green, where children sail it daily on grass.", "What was the ferry built from?", [["🚪","Ruined doors"],["🛢️","Oil barrels"],["🌳","One huge log"]], 0),
  S("y4-32", "The Owl Who Audited the School", "🦉", 830, "An owl moved into the gym rafters and watched everything with examiner's eyes. Pupils began holding doors and picking up litter under that yellow stare. The head teacher, no fool, postponed the owl's eviction indefinitely. When it finally left in spring, it dropped one feather on the trophy shelf, which everyone agreed was a pass mark.", "What did the owl's feather mean to the school?", [["✅","A pass mark"],["🍀","Bad luck"],["✉️","A letter"]], 0),
  S("y4-33", "The Reverse Race", "🏁", 835, "Sports day ended, as tradition demanded, with the Reverse Race: last over the line wins, but you must keep moving. It looked easy and was agony. Children inched like chess pieces, calves burning. Tiny Petra, master of the half-millimetre step, took the crown for the third year running. Her secret training? Walking the dog that sniffs absolutely everything.", "How did Petra train for the race?", [["🐕","Walking a slow, sniffing dog"],["🏃","Sprinting"],["🧘","Standing still"]], 0),
  S("y4-34", "The Postcard Chain", "💌", 840, "It started when Lily sent a postcard to a lighthouse, just to see if anyone replied. The keeper wrote back and enclosed a postcard for her to forward to a desert weather station. The chain grew: a submarine, a circus, an Antarctic base. Two years on, Lily's corkboard holds forty-one cards, and somewhere a stranger is writing card forty-two.", "How did the postcard chain work?", [["➡️","Each reply enclosed a card to forward"],["📦","All cards came at once"],["💻","By email"]], 0),
  S("y4-35", "The Ice Cream Mathematician", "🍦", 845, "Mr Bello's van had a deal: solve his chalkboard puzzle, get a free scoop. Queues formed even in drizzle. Parents pretended to come for the children. The day Keya cracked the unbeaten Saturday Special in her head, he handed her the chalk for keeps. Her first puzzle stumped a maths teacher, two accountants, and, gloriously, Mr Bello himself.", "How could you earn a free scoop?", [["🧮","Solve the chalkboard puzzle"],["🎵","Sing a song"],["🏃","Race the van"]], 0),
  S("y4-36", "The Quietest Place in Town", "🎧", 850, "The museum's new exhibit was an empty, padded room called Silence. Visitors went in skeptical and came out changed, having heard their own heartbeats for the first time. Bookings filled for months. The cleaner, who had worked in the room nightly for years, was interviewed as the town's leading expert. It is not empty, she corrected gently. It is full of you.", "What did visitors hear in the room?", [["💓","Their own heartbeats"],["🎵","Hidden music"],["👻","Whispers"]], 0),
  S("y4-37", "The Great Conker Bank", "🏦", 855, "Conkers were currency at Elm Road School: five bought a swap-card, fifty a friendship bracelet. Then Marcus opened a bank, paying interest in acorns. Economics lessons wrote themselves until spring, when the entire vault, buried for safekeeping, sprouted. The bank collapsed into a grove of seedlings, which the school, after assembly, declared a dividend.", "What happened to the buried conkers?", [["🌱","They sprouted"],["🦝","They were stolen"],["💰","They turned to coins"]], 0),
  S("y4-38", "The Map of Kind Doors", "🚪", 860, "New to town and shy, Amin's grandmother gave him a hand-drawn map. Doors marked in green would always help: the chemist who spoke their language, the neighbour with the spare key, the library desk that never hurried anyone. Years later Amin added doors of his own and passed it to a newer family. The map never shrinks, his grandmother had written. Kindness only adds.", "What did green doors on the map mean?", [["💚","Places that would help"],["🚫","Places to avoid"],["🏪","Shops with sales"]], 0),
  S("y4-39", "The Thunderstorm Choir", "🎶", 865, "Choir practice fell on the night of the big storm, and the hall's electricity failed mid-song. Miss Opal refused to stop: sing with it, not against it. They timed crescendos to thunder, hushed with the rain. A passing dog walker swore the storm itself had joined the choir. Their next concert poster read, with permission of the weather.", "How did the choir use the thunder?", [["🥁","As part of the music"],["🛑","As a signal to stop"],["😱","They hid from it"]], 0),
  S("y4-40", "The Borrowed Grandad Scheme", "👴", 870, "Half the class had grandparents far away; the care home over the road had grandparents missing their grandchildren. The maths was obvious. Friday afternoons became chess, war stories, knitting and outrageous jokes. Test scores rose, though nobody could prove why. Mr Albert, aged ninety-one, claims full credit and has the thank-you cards to back it up.", "What happened on Friday afternoons?", [["🤝","Class visited the care home"],["📝","Extra tests"],["⚽","Football practice"]], 0),
  S("y4-41", "The Upside-Down Map", "🧭", 875, "Geography homework: draw your walk to school. Theo drew his upside down, south at the top, just to see. His teacher pinned it the right way up for him, which made it wrong. The argument that followed taught the class more about maps than the textbook had all term, and ended with the atlas publisher sending Theo a southern-hemisphere map, signed.", "What was unusual about Theo's map?", [["🙃","South was at the top"],["🌈","It was in colour"],["📏","It was tiny"]], 0),
  S("y4-42", "The Lending Tree", "🌳", 880, "The hollow oak by the gate became a give-and-take spot: take an umbrella, leave a paperback; take gloves, leave conkers. Nobody organised it; it simply grew, like the tree. The strangest trade on record: a harmonica left on Monday, and by Friday, a note. Learned three songs. Taking lessons now. Returning it to its destiny. Signed, the postman.", "Who took the harmonica?", [["📯","The postman"],["👮","A police officer"],["🧙","A wizard"]], 0),
  S("y4-43", "The Snow Globe Repair Shop", "🫧", 885, "In her cluttered little shop, Madame Lux carefully repaired snow globes: re-glittering tired blizzards, straightening tiny bent Eiffel Towers, and rehoming miniature skaters who had drifted loose. Fascinated children pressed their noses to her window to watch delicate surgery on these tiny souvenir worlds. She had one curious rule that everyone adored: every repaired globe received one extra figure, hidden somewhere cleverly inside the glass. Finding the secret stowaway, she explained with a knowing smile, is the warranty.", "What did every repaired globe receive?", [["🕵️","A hidden extra figure"],["💸","A discount"],["❄️","Less snow"]], 0),
  S("y4-44", "The Marathon of Small Legs", "🐕", 890, "The sausage dog club announced a marathon: one kilometre, dignity optional. Fourteen long, low athletes wobbled off the start line. There were naps at the halfway water bowl and one unauthorized detour through a sandwich picnic. Winner: Brenda, aged nine, in forty minutes. Every finisher got a rosette and, by popular demand, a sausage.", "How long was the sausage dog marathon?", [["📏","One kilometre"],["🏃","42 kilometres"],["🏠","Around one house"]], 0),
  S("y4-45", "The Window Swap", "🪟", 895, "The art class painted what they saw from their windows: car parks, bins, one lucky river. Then Miss Ines shuffled the paintings between desks. For homework, paint the view you received as if you loved it. Dull car parks returned as robot ballrooms; bins became treasure chests misunderstood. The river, swapped to the boy with the worst view, came back twice as wide.", "What was the homework task?", [["🎨","Paint a swapped view with love"],["📷","Photograph your window"],["🧹","Clean the windows"]], 0),
  S("y4-46", "Captain Calm", "🧘", 900, "Every playtime crisis found its way to Suvi: lost keys, wasp panics, friendship wars. She never rushed, never shouted; she asked her three questions. What happened? What matters most? What is the smallest next step? By July the little ones had renamed her Captain Calm, and the head teacher, after the fire drill mix-up, privately asked for the three questions herself.", "What was Suvi's third question?", [["👣","What is the smallest next step?"],["📣","Who is to blame?"],["⏰","What time is it?"]], 0),
  S("y4-47", "The Library Cat's Apprentice", "🐈‍⬛", 905, "Inkwell the library cat had duties: warming the storytime rug, guarding returned books, judging everyone. When a stray kitten began shadowing him, the librarians watched a strange apprenticeship unfold, rug inspections, shelf patrols, the official window glare. The day Inkwell retired to the sunny office chair, the kitten took the rug at storytime, and not one child noticed the handover.", "What did the kitten learn from Inkwell?", [["📚","The library cat duties"],["🎣","How to fish"],["🚗","How to drive"]], 0),
  S("y4-48", "The Town With Two Clocks", "🕑", 910, "The church clock ran four minutes fast; the station clock, four minutes slow. The town had argued about it for sixty years and, secretly, depended on it: optimists lived by the station, worriers by the church, and everyone made their trains. When a visiting engineer offered to synchronise them, the council thanked him, paid him, and asked him kindly to leave both alone.", "Why did the town keep the wrong clocks?", [["⏰","Everyone made their trains anyway"],["💰","Repairs cost too much"],["🔔","The bells sounded better"]], 0),
  S("y4-49", "The Compost Dragon", "🐲", 915, "The school compost heap steamed on cold mornings, and Reception believed a dragon slept under it. Year Four, who knew about decomposition, were assigned to explain. Instead they built a sign: Dragon sleeping, please add fruit peel quietly. Composting tripled. The science, they reported, can wait a year. The dragon is working.", "What did the sign ask pupils to do?", [["🍌","Add peel quietly"],["🔥","Keep away"],["📸","Take photos"]], 0),
  S("y4-50", "The Last Phone Box", "☎️", 920, "The red phone box made no calls anymore, so the village voted on its future. Greenhouse? Aquarium? It became the Box of Borrowed Courage: inside, notes from neighbours about hard things survived. Read one before your scary thing, the sign said, and leave yours after. Before her hospital visit, Gran left the hundredth note. It is the shortest one: It went fine. Yours will too.", "What did the phone box become?", [["💪","A box of courage notes"],["🐠","An aquarium"],["🌱","A greenhouse"]], 0),
];

const YEAR5: Story[] = [
  S("y5-01", "The Clockmaker's Apprentice", "🕰️", 730, "Every clock in Master Aurelio's shop told a different time, and Lena, his new apprentice, itched to correct them. Each is right for somewhere, the old man said. This one keeps time for Tokyo, that one for her sister in Lima. On her last day of training, Lena found a small brass clock labelled with her own name, already ticking. It keeps the time, Aurelio explained, of wherever you are needed most. It has never once agreed with the clock on her wall, and following it has never led her wrong.", "What was special about Lena's brass clock?", [["🧭","It kept time for where she was needed"],["⏰","It was always fast"],["💰","It was made of gold"]], 0),
  S("y5-02", "The Island That Moved", "🏝️", 740, "The chart said the island should be two miles east, yet there it lay, dead ahead. Captain Reyes checked her instruments twice before the lookout started laughing: the island was breathing. They had anchored beside a sleeping whale so ancient that grass and even small trees grew along its back. The crew spent one impossible afternoon ashore, then slipped away quietly at dusk, leaving no anchor mark, only a logbook entry that no museum has ever agreed to believe.", "Why did the island seem to move?", [["🐋","It was a sleeping whale"],["🌊","The tide carried it"],["🗺️","The map was torn"]], 0),
  S("y5-03", "The Violin in the Wall", "🎻", 750, "Renovating the oldest house on Mill Street, builders found a violin sealed behind the plaster, wrapped in a shawl with a note: for whoever finds her, she is shy, but she sings. The town's music teacher restrung it and gave it to Priya, her quietest student. At the spring concert, Priya played a melody nobody could place, in a key that made the audience think of rain ending. The note, experts later said, was written in 1891. The melody has still not been found in any songbook.", "Where was the violin hidden?", [["🧱","Behind a wall"],["🛏️","Under a bed"],["🌳","Inside a tree"]], 0),
  S("y5-04", "The Night Gardeners", "🌙", 760, "The roses on Cathedral Green were pruned each night, though the council employed no gardener. Suspecting students, the caretaker set up a camera. The footage showed three badgers, working in shifts, snipping deadheads with their teeth and patting the soil flat afterwards. A wildlife professor confirmed it was learned behaviour, passed down for generations; the green had been a monastery garden, and someone, centuries ago, must have gardened with badgers at his heel.", "Who was pruning the roses?", [["🦡","Badgers"],["🧑‍🎓","Students"],["👻","A ghost"]], 0),
  S("y5-05", "The Storm Chef", "⛈️", 770, "Chef Amara's tiny café stood on the cliff road, and on storm nights she refused to close. Fishermen, coastguards, and stranded travellers crowded in, and she fed every one of them, payment or not. Her recipe book had a chapter the others lacked, titled For Weather. Lightning soup. Fog pudding. Bread for the homesick. Food critics never understood her menu, she said, because they only ever visited in sunshine.", "When did Chef Amara refuse to close?", [["⛈️","On storm nights"],["🎄","On holidays"],["🌅","At sunrise"]], 0),
  S("y5-06", "The Atlas of Small Places", "📖", 780, "Most atlases map continents; Iris mapped the territories of her street. The gap in the fence where cats held parliament. The puddle that reflected the bakery sign perfectly at four o'clock. The corner where lost gloves gathered as though migrating. Her notebook filled, then a second, then a ninth. Years later, urban planners consulted her pages before changing a single kerb, because nobody else had ever recorded what the street actually was.", "What did Iris map?", [["🏘️","Small places on her street"],["🌍","The continents"],["🏔️","Mountain ranges"]], 0),
  S("y5-07", "The Frequency of Owls", "📻", 790, "Tuning his grandfather's radio between stations, Sol found a band of soft, rhythmic hooting. The signal strengthened at dusk and vanished by dawn. An ornithologist explained, with delight, that a pair of owls had nested on the old transmission mast, and the microphone left from wartime still worked. All winter, half the town fell asleep to the broadcast. The station never aired an advertisement, and its listeners agree it remains the finest programme ever made.", "What was making the radio sounds?", [["🦉","Owls on the mast"],["👽","A satellite"],["🎙️","A late-night DJ"]], 0),
  S("y5-08", "The Door at Low Tide", "🚪", 800, "Twice a day the sea drew back to reveal a weathered door standing upright in the sand, frame and all, attached to nothing. Tourists photographed it; scientists measured it; the town simply painted it a fresh blue each spring. Old Mrs Penhallow said her grandmother used to knock before beachcombing, out of politeness. Nobody has ever opened it. This is not because it is locked, the harbour sign explains, but because some questions are better kept as neighbours.", "What did the sea reveal at low tide?", [["🚪","A standing door"],["⚓","An anchor"],["🏛️","A temple"]], 0),
  S("y5-09", "The Cartoonist of Platform Two", "✏️", 805, "Nobody knew who drew the tiny chalk cartoons on platform two, but every Monday brought a new one: a pigeon in a bowler hat, the stationmaster rescuing a balloon. Commuters began arriving early. When rain washed one away mid-week, someone left chalk and an apologetic note. The next cartoon showed a cloud handing back a drawing, and the caption: no harm done, it was only borrowed.", "What appeared every Monday?", [["🖍️","A new chalk cartoon"],["🚂","A new train"],["📰","A newspaper"]], 0),
  S("y5-10", "The Hundred-Year Letter", "📜", 810, "The town hall's cornerstone held a letter from the founders, opened at last after a century. The mayor cleared his throat for grand words. Instead the letter read: we argued about everything, even this letter. Be kinder than us, and plant more trees. The crowd laughed, then went quiet. That autumn, the town planted one hundred trees, and the new letter, sealed for the next century, is mostly apologies to squirrels.", "What did the founders' letter advise?", [["🌳","Be kinder and plant trees"],["💰","Save money"],["🏰","Build a castle"]], 0),
  S("y5-11", "The Translator of Babies", "👶", 815, "Nine-year-old Suki claimed she spoke baby. Her cousin's wails meant too many people, the neighbour's meant the sock seam is wrong. Adults chuckled until her predictions kept being right. The health visitor began, unofficially, to consult her. Babies are not confusing, Suki explained, they are just specific. The phrase ended up on a poster in the clinic, credited: S., aged 9, interpreter.", "What did Suki say about babies?", [["🎯","They are just specific"],["😴","They are always tired"],["🤫","They like silence"]], 0),
  S("y5-12", "The Bell Diver", "🔔", 820, "When the old church flooded into the new reservoir, its bell went under with it. Divers said the tower was unsafe and the bell lost. But on still mornings, swimmers reported a faint ringing from below. Engineers blamed currents. The last verger, aged ninety-six, blamed nothing at all. Bells, she said, finish their ringing. That one had two hundred years of Sundays left in it.", "What did swimmers hear on still mornings?", [["🔔","A faint underwater ringing"],["🐟","Fish splashing"],["⛵","Boat engines"]], 0),
  S("y5-13", "The Apology of Captain Hale", "🏴‍☠️", 825, "The museum's pirate exhibit starred Captain Hale, the town's fiercest villain. Then a letter surfaced in an attic: Hale, in shaking handwriting, returning his plunder to a widow, with interest and an apology. Then another letter. Then forty more. The exhibit was awkwardly re-labelled twice, and now ends with a question instead of a verdict: how many stories do we only know the loud half of?", "What did the discovered letters show?", [["💌","Hale secretly returned his plunder"],["🗺️","Where treasure was buried"],["⚔️","Plans for a battle"]], 0),
  S("y5-14", "The Choir of Empty Houses", "🏚️", 830, "The wind through the abandoned terrace made each broken window sing a different note. Most called it eerie; composer Mrs Adeyemi called it a choir without a conductor and wrote down every house's voice. Before demolition day, the whole town gathered as she conducted the street's last concert, doors for percussion. The recording still plays in the new library built there, in a listening booth shaped like a chimney.", "What did Mrs Adeyemi call the singing houses?", [["🎶","A choir without a conductor"],["👻","A haunting"],["🌬️","A draught problem"]], 0),
  S("y5-15", "The Ice House Secret", "🧊", 835, "Behind the manor, the brick ice house had kept winter all summer long, in the days before freezers. Restoring it, volunteers found initials scratched a metre deep in the old frost line, and a tin of marbles. Records showed the ice boy, aged ten in 1890, had worked there alone. The museum placed his marbles in a case, but visitors' children keep leaving new marbles at the door, just in case he wants a game.", "What do visiting children leave at the ice house?", [["🔮","Marbles"],["🧊","Ice cubes"],["🧤","Gloves"]], 0),
  S("y5-16", "The Inventor of the Pause", "⏸️", 840, "Great-Uncle Edmund held a patent, framed in the hall, for a clockwork device that did precisely nothing for ninety seconds. The family thought it a joke until his diary surfaced: sold two hundred units to the telephone exchange, where operators used the Pause before answering angry callers. His slogan was on the box. Ninety seconds now, or ninety minutes later. The family motto, ever since.", "What did Edmund's device do?", [["⏳","Nothing, for ninety seconds"],["📞","Made calls faster"],["🔔","Rang an alarm"]], 0),
  S("y5-17", "The Girl Who Numbered Waves", "🌊", 845, "Nell counted waves the way others counted sheep, and noticed what fishermen knew but never wrote: every seventh swell ran heavier. Her notebook of wave arithmetic, kept through one whole winter on the sea wall, ended up cited in a coastal engineering report. The acknowledgements thank N. Tran, age 10, for observational persistence, which her teacher had previously called daydreaming on official documents.", "What had Nell's teacher called her wave-watching?", [["💭","Daydreaming"],["🔬","Research"],["🏃","Truancy"]], 0),
  S("y5-18", "The Lamplighter's Round", "🏮", 850, "Long after electric lights came, Mr Voss walked the old lamplighter's round each dusk, pausing where every gas lamp had stood. Newcomers assumed he was eccentric. The night of the great power cut, he walked the round with a lantern, and the whole street followed him like ducklings, lighting candles at each remembered post. Some routes, the paper wrote next day, stay lit longer than their lamps.", "What happened during the power cut?", [["🕯️","The street followed his round with candles"],["😴","Everyone stayed home"],["🚒","Firefighters came"]], 0),
  S("y5-19", "The Borrowers' Bakery", "🍞", 855, "The bakery ran a quiet ledger: bread now, pay when you can. The baker's daughter, doing accounts, found columns that never balanced and asked her father why he tolerated it. He showed her the back pages: debts repaid decades late, in apples, apprenticeships, a roof mended in secret. Bread is quick arithmetic, he said. People are long division. She runs the bakery now. The ledger continues.", "How did some customers repay old debts?", [["🍎","In apples and favours"],["💷","Always in cash"],["❌","They never did"]], 0),
  S("y5-20", "The Museum of Almost", "🏛️", 860, "The strangest museum in the county displayed near-misses: the umbrella forgotten just before the downpour, the lottery ticket one number off, the letter posted to the wrong twin that started the right friendship. Visitors left laughing or thoughtful, usually both. The final case stood empty except for a mirror and a label: exhibit pending. What almost happened to you today?", "What was in the museum's final case?", [["🪞","A mirror"],["💎","A diamond"],["🎟️","A ticket"]], 0),
  S("y5-21", "The Weather Boat", "⛵", 865, "Old Salt Marie predicted weather better than the radio, reading it from her moored boat: tight ropes meant dry air, certain creaks meant a blow from the east. Scientists visited with instruments and left puzzled; her boat outperformed their barometer. The truth was forty years of listening. The boat has the data, she said, tapping the mast. I am only the speaker it found.", "How did Marie predict the weather?", [["👂","By her boat's ropes and creaks"],["📡","With radar"],["🔮","With a crystal ball"]], 0),
  S("y5-22", "The Tunnel of Held Breaths", "🚇", 870, "Every child in town knew the rule: hold your breath through the old railway tunnel and your wish stays alive. Engineers found the tunnel structurally pointless and scheduled it for filling. The protest was led, to everyone's surprise, by grandparents, arriving with sixty years of kept wishes to testify. The tunnel stands. The council minutes record the deciding argument in full: where else do wishes get practice?", "Who led the protest to save the tunnel?", [["👴","Grandparents"],["🧒","Schoolchildren"],["👷","Engineers"]], 0),
  S("y5-23", "The Counterfeit Spring", "🌸", 875, "February dragged grey and endless, so the florist filled her window with silk blossom and turned on a recording of birdsong. Fraud, smiled the postman, but he slowed down daily. The café followed with paper tulips; the butcher, improbably, with origami swans. By the time real spring arrived, it found the whole street already rehearsed, and, the florist insisted, slightly jealous.", "How did the street fight the grey February?", [["💐","With fake blossom and birdsong"],["✈️","By going on holiday"],["😴","By sleeping more"]], 0),
  S("y5-24", "The Encyclopedia of Grandmothers", "📚", 880, "For her project on local history, Femi interviewed one grandmother. Then her friends' grandmothers. Then strangers' grandmothers, by appointment. Each got a page: wars survived, recipes guarded, dances remembered, advice dispensed. The school printed three copies; the library demanded ten. Volume Two is underway, delayed only because every interview, Femi reports, ends with compulsory cake.", "Why is Volume Two delayed?", [["🍰","Every interview ends with cake"],["💻","The computer broke"],["📦","No paper left"]], 0),
  S("y5-25", "The Silent Auctioneer", "🤝", 885, "Auctioneer Briggs lost his voice the morning of the charity sale and refused to cancel. He auctioned everything in mime: galloping for the rocking horse, conducting for the gramophone, weeping theatrically over the onion crate. Bidders laughed until they doubled their offers. It became the town's biggest fundraiser ever, and Briggs, voice recovered, was asked, gently, to lose it again next year.", "How did Briggs run the auction?", [["🎭","In mime"],["📢","With a megaphone"],["✍️","By notes"]], 0),
  S("y5-26", "The Orchard of First Days", "🍎", 890, "A tree for every first day of school: the village had planted one per child for ninety years. Each child knew their tree, measured against it, climbed it when permitted, carved nothing. When storms took the oldest oak, the village rang its former owner, now ninety-six. She arrived with a sapling and an old photograph, and the two were planted together. First days, she said, are perennials.", "What did the village plant for every child?", [["🌳","A tree on their first school day"],["🌹","A rose at birth"],["🥔","Potatoes"]], 0),
  S("y5-27", "The Committee of Sparrows", "🐦", 895, "Outside the bakery, sparrows held what locals called committee meetings, debating crumbs with parliamentary fury. The baker named the regulars: the Chairman, the Treasurer, the Member for the Gutter. Tourists were briefed solemnly. When the council proposed moving the benches, four hundred residents objected on behalf of, the petition stated, sitting members. The benches stayed. Democracy, the paper noted, is for the birds.", "What did locals call the sparrow gatherings?", [["🏛️","Committee meetings"],["🎵","Concerts"],["⚔️","Battles"]], 0),
  S("y5-28", "The Smallest Bookshop", "📕", 900, "The bookshop was a converted phone box: one shelf, twelve books, an honesty tin. The owner restocked it by bicycle, choosing each dozen like a chef plans a menu. Take one, leave one, or leave a note saying what you wish were here. The wish notes became famous; she filled them weekly. The box has sold no bestsellers and changed, at last count, several hundred lives.", "How were the twelve books chosen?", [["🚲","Carefully, like a menu"],["🎲","At random"],["📦","Whatever was donated"]], 0),
  S("y5-29", "The Tide Clock", "🕰️", 905, "Inland children visiting the coast asked what the strange clock in the harbour office measured; it had one hand and the numbers made no sense. The harbourmaster explained tides, then bet them they would feel it within a week. He was right: by Friday they woke knowing the water was out, the way you know a Sunday. Some clocks, he said, install themselves in you.", "What did the strange clock measure?", [["🌊","The tides"],["🌡️","Temperature"],["💨","Wind speed"]], 0),
  S("y5-30", "The Repair Café", "🔧", 910, "Saturday mornings, the scout hut became the Repair Café: broken toasters, lame chairs, silent radios, all welcome. The fixers were retired engineers, a watchmaker, and lately a row of fascinated children passing screwdrivers. The rule was that owners had to watch and learn. We do not mend things, the watchmaker corrected a reporter. We mend the idea that things are over.", "What was the Repair Café's rule for owners?", [["👀","Watch and learn"],["💰","Pay double"],["🚪","Wait outside"]], 0),
  S("y5-31", "The Atlas Moth", "🦋", 915, "The science cupboard's mystery cocoon, inherited from a retiring teacher with a note saying patience, hung for months. The morning it opened, lessons stopped. An atlas moth, wings like brown maps of imaginary coasts, dried itself against the geography poster as if checking its bearings. It lived its brief, enormous week as school royalty, and the new science teacher now signs her notes the same way: patience.", "What emerged from the cocoon?", [["🦋","An atlas moth"],["🐛","A caterpillar"],["🐝","A bee"]], 0),
  S("y5-32", "The Night the Statues Walked", "🗿", 920, "April the first: the town's statues all wore knitted scarves, and small footprints in flour led between them. The Founders Statue held a thermos. Children swore the statues had visited each other. Investigators identified wool from four grandmothers' stashes, but every grandmother had an alibi: they were, all night, knitting. The case remains open, festively, forever.", "What did the statues wear that morning?", [["🧣","Knitted scarves"],["🎩","Top hats"],["👟","Trainers"]], 0),
  S("y5-33", "The Borrowed Orchestra", "🎺", 925, "The school had talent but no instruments; the regiment band had instruments but, after disbanding, no players. The colonel arrived with a lorry and one condition: each instrument came with its history. The trumpet that sounded the harvest fair. The drum from two coronations. At concerts, the programme lists each player and each instrument's past, and both, the conductor says, perform.", "What came with each donated instrument?", [["📜","Its history"],["🎵","Sheet music"],["💷","Money"]], 0),
  S("y5-34", "The Igloo on Market Square", "🧊", 930, "The freak snowfall buried the market, so the traders, snowed in together, built an igloo from stall-table snow bricks, engineered by the fishmonger who had once wintered in Norway. They sold hot chocolate through its window for three glorious days. The thaw took it, as thaws do. The crooked photo of fourteen frozen grinning traders hangs in the market office, labelled: branch office.", "Who engineered the igloo?", [["🐟","The fishmonger"],["🥖","The baker"],["👮","A police officer"]], 0),
  S("y5-35", "The Apprentice Rainmaker", "🌧️", 935, "Grandfather watered with a divining grin, claiming he could call rain by whistling low. Kavi tested it scientifically: notebook, dates, controls. Whistling days, rain followed sixty percent; silent days, twenty. Coincidence, said her teacher. More data, said Kavi. Three summers in, the spreadsheet is vast, the mystery intact, and Grandfather, asked for comment, only whistles.", "What did Kavi use to test Grandfather's claim?", [["📓","A notebook and data"],["🎱","A magic ball"],["📺","The TV forecast"]], 0),
  S("y5-36", "The Lost Property Sea", "🧤", 940, "The ferry's lost property room held thirty years of forgetting: gloves, umbrellas, one wedding hat, a message in a bottle never thrown. The new clerk, instead of auctioning it, mounted an exhibition with invented histories beside each item. Owners began arriving, correcting labels, telling truer stories. Half the items went home. The other half stayed, the clerk says, because their stories grew better than their owners' memories.", "What did the clerk put beside each item?", [["🏷️","Invented histories"],["💲","Price tags"],["🔒","Locks"]], 0),
  S("y5-37", "The Hill That Hummed", "⛰️", 945, "On certain west-wind days, Benton Hill hummed a low note you felt in your teeth. Geologists found the cave mouth that made it: the hill was a flute the wind occasionally remembered. The town tuned its church bell to harmonise, which scandalized the diocese and delighted everyone else. Now west-wind days are minor local holidays. Work slows. People listen. The hill, indifferent, plays on.", "What made the hill hum?", [["🌬️","Wind across a cave mouth"],["🚇","Trains underground"],["🐝","Giant bees"]], 0),
  S("y5-38", "The Two-Minute Museum", "⏱️", 950, "It opened in a former lift shaft: one exhibit, one visitor at a time, two minutes. The exhibit changed weekly and was never announced. A single perfect autumn leaf. A photograph of a stranger laughing. Your own reflection with the caption, current acquisition. The queue became a town institution, defended fiercely. Brevity, reads the visitor book's most-quoted entry, is the longest exhibition I have attended.", "How long was each visit?", [["⏲️","Two minutes"],["🕐","One hour"],["📅","All day"]], 0),
  S("y5-39", "The Carthorse Clock", "🐴", 955, "Long retired, Duchess the carthorse still stopped at every house on her old bread round when walked, timing the route to the minute without a watch. New residents learned their address's history from where she paused. When the bakery centenary came, Duchess led the parade along the round, halting at each door while the crowd, instructed by the oldest residents, applauded the stops as much as the walking.", "How did Duchess reveal the old bread round?", [["🛑","She stopped at every old house"],["🥖","She carried bread"],["🔔","She wore a bell"]], 0),
  S("y5-40", "The Glasshouse Postman", "🌡️", 960, "Letters addressed to The Gardener, Botanic Glasshouse arrived from around the world: questions, seeds, confessions of killed cacti. The post office, finding no such employee, nearly returned them all, until the volunteer who actually watered the ferns began answering. Forty years on, her replies are collected in three volumes, and the post office has a dedicated shelf labelled, simply, Gardener.", "Who answered the glasshouse letters?", [["🪴","The volunteer who watered ferns"],["👔","The director"],["🤖","A machine"]], 0),
  S("y5-41", "The Half-Built Ship", "🚢", 965, "The shipyard closed mid-build, leaving a half-ship rusting on the slipway like an unfinished sentence. The town argued for a decade: scrap or shrine? The art school answered first, mooring lights along the exposed ribs. Then came the choir, the night markets, the weddings. The ship never sailed; instead, the town learned to sail through it, which the last shipwright declared, before he died, a better launch than most.", "What happened to the half-built ship?", [["🎭","The town filled it with life"],["⚓","It finally sailed"],["🔨","It was scrapped"]], 0),
  S("y5-42", "The Thousand-Crane Window", "🪟", 970, "When Mr Sato's shop window broke, the street expected plywood. Instead came a glass case, slowly filling with paper cranes folded from his late wife's magazines, one per morning, in the window where she had arranged flowers. At one thousand cranes, tradition grants a wish. The street watched the count for three years. On the morning of the thousandth, the window held a sign instead: wish granted. Thank you for counting with me.", "What did the thousandth-crane sign say?", [["🙏","Wish granted, thank you"],["🔒","Shop closed"],["💰","Cranes for sale"]], 0),
  S("y5-43", "The Geometry of Geese", "🦢", 975, "Why the V? Tariq's homework question outgrew the textbook answer. He cycled to the reservoir at dawn for a month, sketching formations: the V, yes, but also the J of crosswinds, the brief W of arguments. His teacher posted the sketchbook to an ornithology journal half in jest. The reply, addressed to Mr T. Aziz, researcher, hangs framed above his desk beside his first homework, marked: see me.", "What did Tariq sketch at the reservoir?", [["📐","Goose flight formations"],["🌅","Sunrises"],["🚲","Bicycles"]], 0),
  S("y5-44", "The Lighthouse Exchange", "💡", 980, "The twinned towns, one on each side of the cold strait, could see each other's lighthouses but had never met. The keepers began a Morse correspondence after hours: weather, chess moves, recipes flashed across thirty dark miles. When automation ended their posts the same year, both towns learned the lamps had also been flashing, for decades, one extra nightly word each way: neighbour.", "What extra word did the lighthouses flash nightly?", [["🤝","Neighbour"],["⚠️","Danger"],["💤","Goodnight"]], 0),
  S("y5-45", "The Salt Path Painter", "🎨", 985, "Every summer, someone painted a thin white line from the village square to the sea, three miles through lanes and fields, and every autumn the rains took it. No council approved it; no artist claimed it. Families walked the line barefoot on the first hot day, a procession nobody organised. The year it failed to appear, the village painted it themselves, in one afternoon, and discovered there had never been a someone. There had been everyone, taking turns without knowing.", "Who had been painting the line all along?", [["👥","Different villagers, unknowingly taking turns"],["🎨","One secret artist"],["🏛️","The council"]], 0),
  S("y5-46", "The Winter Swimmers", "🏊", 990, "They met at dawn by the lake, December through February: the retired judge, the nurse, the boy doing his award, the baker still floury. The water was iron; the ritual, warmer. Newcomers were taught the rules: in slowly, out singing, cake compulsory. When the boy moved away, he wrote that university was fine but no one there understood about the singing. The reply, signed by all of them, said: the lake holds your place.", "What was compulsory after swimming?", [["🍰","Cake"],["😴","A nap"],["🏃","A run"]], 0),
  S("y5-47", "The Library Phantom's List", "📋", 995, "Books at the library kept being reshelved into impossible, perfect arrangements: novels beside the biographies of their authors, atlases beside explorers' diaries. The librarians hunted their phantom for a year before finding the night cleaner's notebook of pairings, with reasons. They offered her a job. She declined, on the grounds that daylight would spoil her system, but agreed to leave the notebook open, one page a week, as a public service.", "Who was rearranging the books?", [["🧹","The night cleaner"],["👻","A ghost"],["📚","The librarians"]], 0),
  S("y5-48", "The Mountain's Mailbox", "📫", 1000, "At the summit cairn stood a tin box with a ledger: name, date, and one sentence for the mountain. Some wrote jokes; some wrote griefs; one entry simply said, again, yearly, for fifty-two years. When the box filled, volumes went to the village archive, where winter evenings were spent reading the mountain's correspondence aloud. The current ledger's first page bears the archivist's note: the mountain replies, but slowly. Look around.", "What did people leave in the summit box?", [["✍️","One sentence for the mountain"],["🪙","Coins"],["📸","Photographs"]], 0),
  S("y5-49", "The Weaver of Worn Words", "🧶", 1005, "Mrs Iqbal collected the words her customers' grandparents could no longer say after strokes or distance or death, and wove them, in thread, into the hems of mended clothes. A father's nickname for his daughter, hidden in a school skirt. A grandmother's blessing, in a wedding suit lining. Visible to no one, the wearer always knew. Her mending cost the same as anyone's. The words, she said, threading another needle, were already paid for.", "Where did Mrs Iqbal hide the woven words?", [["🪡","In the hems and linings"],["🏷️","On the labels"],["👝","In the pockets"]], 0),
  S("y5-50", "The Last Day of the Pier", "🎡", 1010, "Condemned and fenced, the old pier had one final day before demolition, and the town queued at dawn. The arcade gave its prizes away; the fortune teller told only good ones; the brass band played until the tide came in twice. At sunset, the oldest resident, who had danced there at fourteen, was carried the length of the boards in a fishing chair, calling the structure, fondly, late for its own funeral. It fell the next week. The dancing, by general agreement, did not.", "What did the fortune teller do on the last day?", [["🔮","Told only good fortunes"],["🚪","Stayed closed"],["💰","Doubled her prices"]], 0),
];

const YEAR6: Story[] = [
  S("y6-01", "The Archivist of Sounds", "🎧", 830, "Before the old market was demolished, Ms Okafor walked its aisles with a recorder: the fishmonger's banter, the squeal of the third trolley, rain on the corrugated roof. People thought the project sentimental until the new mall opened, efficient and silent, and a strange grief settled on the town. Her archive became the most requested collection in the library's history. We preserve photographs of how things looked, she told the council, accepting their apology and a small grant. Somebody must keep how things sounded, or half of every memory is lost.", "What did Ms Okafor preserve?", [["🔊","The sounds of the market"],["📷","Photographs"],["🧱","The market bricks"]], 0),
  S("y6-02", "The Postal Chess Match", "♟️", 850, "In 1962, two lighthouse keepers began a chess match by post, one move per letter, their boards forty miles of sea apart. Storms delayed moves for months; one knight travelled via three sorting offices and a fishing trawler. Both men retired, then their children continued the game, then a granddaughter and a grandson who had never met. The fifty-eighth move was played last spring, at a small ceremony where the two families finally shared a table. The game, everyone agreed, must on no account be allowed to finish.", "How was the chess match played?", [["✉️","By letters in the post"],["💻","Over the internet"],["📞","By telephone"]], 0),
  S("y6-03", "The Cartographer's Error", "🧭", 870, "The 1851 survey of the county contains a famous mistake: a lake, two miles wide, where there has only ever been pasture. Historians blamed brandy or boredom, until a researcher noticed the surveyor's diary entry for that week: my daughter asks why maps never show the places we wish existed. Reader, I have given her one. The error was reprinted for ninety years before anyone dared correct it, and the field is called The Lake to this day by everyone local.", "Why did the surveyor draw a lake?", [["👧","For his daughter's wish"],["🥃","He drank brandy"],["🌫️","He saw a mirage"]], 0),
  S("y6-04", "Telling the Bees", "🐝", 890, "There is an old custom that bees must be told the news of the house, or they will leave. When the orchard changed owners, young Mr Webb thought the ritual nonsense, until the hives emptied within a week. His neighbour, ninety and unsurprised, walked him to the empty boxes and had him introduce himself aloud, apologise for the delay, and describe his plans for the apple trees. The bees returned eleven days later. Science offers several explanations. Mr Webb, who now tells the hives everything, has stopped asking for one.", "What happened when the bees were not told the news?", [["🐝","They left the hives"],["🍯","They made more honey"],["😴","They fell asleep"]], 0),
  S("y6-05", "The Timetable Poet", "🚂", 910, "Nobody knew who amended the station's departure boards, but each delay announcement arrived with a line of verse: the 8.14 is late, as spring is late, worth waiting for. Commuters began missing earlier trains on purpose. The rail company, after a brief investigation, discovered the culprit was the announcer herself, a retired literature teacher, and faced a difficult decision: passenger satisfaction had risen forty percent. She was issued a formal warning and, in the same envelope, a request for a Christmas special.", "Who was writing the poems?", [["🎙️","The announcer"],["🧑‍✈️","A train driver"],["🕵️","A passenger"]], 0),
  S("y6-06", "The Colour That Has No Name", "🪟", 930, "The cathedral's west window holds a blue that restorers cannot reproduce. The medieval glassmakers left recipes for every other pane, but for this one only a note: as the sky, the third morning after grief. Chemists have analysed it; artists have approximated it; tourists photograph it and find their pictures turn out merely blue. The head restorer keeps the original fragment in a velvet drawer and has concluded, after thirty years, that some instructions are not measurements but memories, and that the window is best mended by people who have had such mornings.", "What could the restorers not reproduce?", [["🟦","The blue colour"],["🖼️","The window's shape"],["⛪","The stone arch"]], 0),
  S("y6-07", "The School Boat", "⛵", 950, "For sixty years, the children of the scattered islands were rowed to school by Mr Brand, in fair weather and foul, his boat doubling as library, infirmary, and confession box for unfinished homework. When he retired, the council proposed a bridge. The islanders voted instead to train four young boat keepers, reasoning that a bridge carries bodies but a boatman carries childhoods. The first of the four is Mr Brand's granddaughter, who keeps a tin of barley sugar under the stern seat, exactly where it has always been.", "What did the islanders choose instead of a bridge?", [["🚣","Training new boat keepers"],["🌉","A smaller bridge"],["🚁","A helicopter"]], 0),
  S("y6-08", "The Unfinished Symphony Room", "🎼", 970, "The music museum's strangest exhibit is an empty room. On the walls hang manuscripts abandoned mid-bar: a symphony stopped by war, a lullaby interrupted by good news, a quartet whose composer simply went out for bread and never wrote another note. Visitors are given a pencil at the door. The guest books are full of endings, clumsy, brilliant, heartfelt, and once a year the city orchestra performs the best of them. The originals remain unfinished. That, says the curator, is the exhibit.", "What are visitors given at the door?", [["✏️","A pencil"],["🎻","A violin"],["🎟️","A ticket"]], 0),
  S("y6-09", "The Debt of Whitcombe Bridge", "🌉", 980, "Carved into the keystone of the bridge, almost worn away: built by the village that could not pay, for the mason who would not wait. Parish records complete the story. The mason, owed a fortune the flooded village no longer had, accepted instead a promise: every household, forever, would keep one traveller's need met, a meal, a bed, a mended wheel. Two centuries on, the bridge stands, and the village still argues, contentedly, over whose turn it is to honour the mortgage.", "How did the village pay the mason?", [["🤝","A promise of hospitality forever"],["💰","In gold, eventually"],["🐑","With sheep"]], 0),
  S("y6-10", "The Glossary of Grandfather", "📔", 990, "After Grandfather's memory began to slip, Amara started a glossary of his words before they went: the name he called the wind off the harbour, the verb he used only for badly parked cars, his term for the silence after good soup. The notebook grew into family law; her cousins contributed entries by post. At the funeral, the eulogy was simply twelve definitions, read slowly. Linguists call such words idiolect. Amara's notebook calls them, on its first page, the dialect of one beloved speaker.", "What did Amara collect in her notebook?", [["💬","Grandfather's own words"],["📷","Photographs"],["🧾","Receipts"]], 0),
  S("y6-11", "The Auction of Empty Frames", "🖼️", 1000, "Lot one: gilt frame, contents lost in the fire of 1911. The auction of the burned gallery's surviving frames was expected to fail. Instead, bidding soared as families bought frames for what they chose to remember: a frame for a soldier's last leave, for a demolished farmhouse, for a marriage proposal nobody photographed. The catalogue's afterword, written by the auctioneer, is studied in art schools now. We did not sell frames, it concludes. We sold the permission to hang what cannot be hung.", "What did people buy the empty frames for?", [["💭","To frame their memories"],["🔥","As firewood"],["💰","To resell"]], 0),
  S("y6-12", "The Seventeen-Year Orchestra", "🦗", 1010, "The summer the cicadas emerged, after seventeen years underground, the town's composer did not complain about the noise. She wrote around it, a suite in the insects' key, premiered outdoors where the swarm supplied the continuo. Reviewers called it unrepeatable. She agreed, scheduling the second performance for the next emergence. Tickets for a concert seventeen years away sold out in a week, many bought for children not yet born, which the composer called the most optimistic thing an audience has ever done.", "When is the second performance scheduled?", [["🗓️","Seventeen years later"],["🎄","Next Christmas"],["🌙","Never"]], 0),
  S("y6-13", "The Ledger of Small Bravery", "📒", 1020, "The retiring headteacher's office held a locked drawer and, it turned out, forty years of notes: every small courage she had witnessed and never mentioned. Asked the question aloud though terrified. Sat beside the new boy, first day. Returned to the diving board, second try. Names, dates, no grades. The school debated publishing it and decided instead to continue it, a duty passed to each head like a crown. Children still do not know it exists, which, the first entry explains, is the entire point.", "What did the headteacher record for forty years?", [["🦁","Small acts of courage"],["📉","Test results"],["🚫","Rule breaking"]], 0),
  S("y6-14", "The Reservoir Villages", "🏞️", 1030, "Beneath the reservoir lie two drowned villages, rivals for six hundred years before the water settled their feud. In drought summers, when the old walls surface, descendants of both walk the mudflats together, mapping kitchens and chapels for the archive. The water authority once proposed a memorial plaque; both descendant societies, in their only recorded agreement before that day, rejected it. The villages, their joint letter said, are not under the water. They are why we are standing together above it.", "When do the old villages reappear?", [["☀️","In drought summers"],["🌑","At night"],["❄️","In winter"]], 0),
  S("y6-15", "The Apology Bell", "🔔", 1040, "The monastery bell, legend held, rang true only when rung in apology. The science was acoustic, something about a flaw in the casting answering a hesitant pull, but the custom outlived the explanation. For centuries, quarrels in the valley ended with a walk up the bell path, an unasked-for chore done at the foot of the tower, and one clear note. The bell cracked in 1972 and was recast with the same flaw, deliberately, at the foundry's insistence. Perfection, their invoice noted, was not what this instrument is for.", "What was the bell recast with?", [["💔","The same deliberate flaw"],["✨","Pure silver"],["🔇","A muffler"]], 0),
  S("y6-16", "The Longest Borrow", "📕", 1050, "The book returned to the library seventy-three years late, with an envelope of apology and a savings book: the borrower had deposited the fine, sixpence weekly, her whole adult life, the account growing past any sensible debt into a bequest. She had been evacuated mid-loan in 1944, the letter explained, and the book, a collection of poems, had kept her company through everything since. The library waived the fine, funded a poetry shelf with the bequest, and reissued the book to her granddaughter, stamped: returnable whenever it has finished its work.", "What had the borrower saved her whole life?", [["🪙","The growing library fine"],["📚","Other books"],["✉️","Letters"]], 0),
  S("y6-17", "The Translator of Silence", "🤟", 1060, "When the deaf school closed, its last teacher took a job no one understood, at the courthouse, the hospital, wherever called: not interpreting sign, exactly, but translating silences, the difference between a witness's fearful pause and an honest searching one, between a patient's no and not yet. Officials were skeptical until her record spoke: misunderstandings collapsed wherever she sat. Asked her qualification, she would sign, then patiently translate herself: forty years of listening with my eyes.", "What did the teacher translate?", [["🤫","Silences and pauses"],["📜","Old documents"],["🌍","Foreign languages"]], 0),
  S("y6-18", "The Orchard of Spare Hours", "🍐", 1070, "The factory's retired night shift, finding daytime sleep impossible, met at three a.m. in the abandoned orchard with thermoses and secateurs. Within five years, the wild pears were famous and the night gardeners had a waiting list: insomniacs, new parents off duty, the recently bereaved. No one was required to talk. The orchard's honesty stall, open only before dawn, bears a painted motto that the town quotes at every difficulty since: some hours are not empty. They are spare.", "Who gardened the orchard at 3 a.m.?", [["🌙","Retired night-shift workers"],["🦉","Owls"],["🧑‍🌾","Paid gardeners"]], 0),
  S("y6-19", "The Examination of Clouds", "☁️", 1080, "Question seven of the 1958 scholarship paper became legend: describe the sky outside the window. Whole essays survive in the archive, some by future poets, one by a future meteorologist whose answer ran to equations, one by a farm boy who wrote a single sentence the examiners passed around in silence and marked, against every rule, at full marks. The sentence is displayed at the school each exam season, uncaptioned: it has rained, the sky is sorry, and my father's barley is saved.", "Which answer received full marks?", [["🌾","The farm boy's single sentence"],["🧮","The equations"],["📜","The longest essay"]], 0),
  S("y6-20", "The Custodian of Echoes", "🏟️", 1090, "When the old stadium was demolished, the club's groundskeeper requested one thing: an hour alone inside, first. Cameras caught him at the centre circle, eyes shut, turning slowly, and the clip travelled the world captioned with guesses. He explained only once, to a local boy who asked. Every roar stays in a ground, son. I was deciding which ones to take with me. The new stadium hired him to choose where the dressing room speakers go. Acoustics, reads his contract. Echoes, reads his business card.", "What did the groundskeeper say stays in a ground?", [["📣","Every roar"],["⚽","Old footballs"],["🌱","The grass seed"]], 0),
  S("y6-21", "The Inheritance of Keys", "🗝️", 1100, "The locksmith died leaving her son four hundred labelled keys to locks that no longer existed: demolished theatres, melted safes, a diary lost at sea. The auctioneer valued the collection at nothing. The son hung them in the shop window instead, each with its label, and watched strangers stop daily to read: rear door, Alhambra, stage left. People, he discovered, will queue to mourn doors. The collection is now insured for a sum the auctioneer declines to discuss.", "What did the keys open?", [["🚫","Locks that no longer exist"],["🏦","Bank vaults"],["🚪","The shop"]], 0),
  S("y6-22", "The Weather Diary of Room 9", "🌦️", 1110, "Every class to pass through Room 9 since 1931 had added to the weather diary, one line per school day, no exceptions: snow, the inspector slipped; heatwave, ink dried mid-word; the entry for one wartime morning says only, sirens, but sunny after. Climate researchers found it last year, ninety unbroken years of amateur data, and called it priceless. The current Year Six, unimpressed by fame, guard the older privilege: the diary is written standing at the window, and the writer chooses the words alone.", "Why did researchers value the diary?", [["📊","Ninety years of unbroken weather data"],["✍️","Its beautiful handwriting"],["💷","Its leather cover"]], 0),
  S("y6-23", "The Pilot of Paper Planes", "🛩️", 1120, "Grounded by the war wound nobody saw him acquire, the airline pilot taught the hospital children aerodynamics with paper darts down the long ward. Records of his year there survive in the children's letters: flight plans filed for journeys to the kitchen, boarding passes for beds, a logged emergency landing in matron's tea. Sixty years on, the ward's successor unit still launches a paper plane from the window each spring, with clearance, the consultant insists, from a tower that no longer answers but has never once objected.", "What did the pilot teach the children with?", [["✈️","Paper darts"],["📚","Textbooks"],["🎮","Games"]], 0),
  S("y6-24", "The Census of Small Gods", "🏠", 1130, "The folklore student's project counted household guardians the modern town swore it did not believe in: the horseshoe nailed open-end up, the coin under the new doorstep, the first slice given to the dog for luck. Four hundred houses; three hundred and eighty-one observances, most performed by people who called them habit, not belief. Her thesis passed with distinction and one examiner's note, now framed: belief, it seems, has merely learned to introduce itself as habit, and your town is devout.", "What did most people call their lucky customs?", [["🔁","Habit"],["🙏","Religion"],["🎭","Performance"]], 0),
  S("y6-25", "The Choirmaster's Last Lesson", "🎹", 1140, "Losing his hearing by degrees, the choirmaster reorganised the choir without explanation: the strongest voices moved beside the newest, the nervous beside the kind. Only at his farewell concert, conducted in near-total deafness, did the design show itself, every singer holding another steady, the sound carrying him as much as his baton carried it. His successor found a single instruction left in the piano stool. Seat them so that no one sings alone. The rest is repertoire.", "What was the choirmaster's final instruction?", [["🤝","Seat them so no one sings alone"],["🎵","Sing louder"],["🧹","Tidy the music room"]], 0),
  S("y6-26", "The Border Bakery", "🥨", 1150, "The bakery straddled the border exactly: ovens in one country, counter in the other. Two sets of inspectors, two currencies, one bread queue that history's worst decades never managed to divide. When the crossing closed in the bad years, the law forbade passage but said nothing of loaves, and the baker's long wooden peel passed bread over the painted line, daily, for eleven years. The peel hangs in the regional museum now, labelled by treaty, as both nations insisted: instrument of unbroken neighbourliness.", "What passed over the border for eleven years?", [["🍞","Bread on the baker's peel"],["📦","Smuggled goods"],["✉️","Secret letters"]], 0),
  S("y6-27", "The Astronomer of One Star", "🌟", 1160, "Officially, Miss Petrov's life work was unremarkable: forty years of nightly measurements of a single unremarkable star. Colleagues chased comets and tenure; she logged her star's small moods through revolution, marriage, grief, and three telescopes. The week she died, the star brightened, a once-in-centuries flare, and her uninterrupted record became the only complete account on Earth, cited now in every textbook. The final page of her log, written in hospital, is displayed beside her chair at the observatory. Keep watching. Everything ordinary is patient.", "Why did her record become priceless?", [["📈","It was the only complete account of the star's flare"],["💎","It was written in gold ink"],["📚","It was very long"]], 0),
  S("y6-28", "The Committee for Unimportant Things", "📎", 1170, "Founded as a joke after a heated council meeting about bunting, the Committee for Unimportant Things met monthly to handle whatever the real council laughed out of session: the duck crossing signage, the bench that faced the wrong way, the missing apostrophe on the war memorial that one widow minded terribly. Within a decade it had quietly become the most loved institution in town, and its founding minutes, mock-solemn at the time, read now like prophecy: small things are how a place says it is paying attention.", "What did the committee handle?", [["🦆","Things the council laughed off"],["💰","The town budget"],["🚓","Crime"]], 0),
  S("y6-29", "The Glassblower's Breath", "🫙", 1180, "Each apprentice's final test at the old glassworks was a sealed vessel containing nothing but their own breath, blown at the moment the master judged them ready. Shelves of them survive, labelled by name and date, the air of long-gone lungs held in glass. When the works closed, descendants came from three continents to claim their ancestors' breath. Customs forms struggled. Contents, one official finally wrote, accepting the impossibility with a stamp: one breath, taken at the moment of mastery. Value: see owner's face.", "What did each sealed vessel contain?", [["💨","The apprentice's breath"],["💧","Holy water"],["🏖️","Coloured sand"]], 0),
  S("y6-30", "The Stationmaster's Garden", "🌼", 1190, "The branch line closed in 1966, but the stationmaster, pensioned and unpersuaded, kept the platform garden to timetable: bulbs in by the autumn express that no longer ran, hanging baskets up for a summer service of ghosts. Ramblers found the absurd, immaculate platform deep in the woods and word spread. The heritage railway that eventually relaid the track insists it was the garden that kept the route alive in memory long enough to save. His successor is titled, officially, Keeper of the Timetable of Flowers.", "What did the stationmaster keep to timetable?", [["🌷","The platform garden"],["🚂","The trains"],["⏰","The station clock"]], 0),
  S("y6-31", "The Quiet Carriage", "🚃", 1200, "The 7.42 had an unofficial institution: the third carriage, silent by custom older than any signage, where the same strangers had shared wordless company for years. When the new operator's refit threatened open-plan everything, the carriage's commuters, who had never spoken, organised by note. Their petition, four hundred signatures gathered in perfect silence, included testimony that moved the board: in that carriage I grieved unobserved, studied unmocked, and once, quietly, decided to live differently. We do not know each other's names. We are nonetheless company.", "How did the silent commuters organise?", [["📝","By passing notes"],["📢","By shouting"],["💻","Online"]], 0),
  S("y6-32", "The Inventory of the Tide", "🐚", 1210, "Twice daily for thirty years, the beachcomber logged what the tide returned: nets, dolls, once a wedding dress, sea glass by the jarful. Her ledgers, donated to the maritime museum, turned out to chart currents more precisely than any instrument of her era; ocean scientists still mine them. But the museum's most visited page is an entry from her hardest year, displayed under glass: today the sea brought back nothing I lost. Logged anyway. The sea is not finished.", "What did scientists find in her ledgers?", [["🌊","Precise records of ocean currents"],["🗺️","Treasure maps"],["🐟","Fish recipes"]], 0),
  S("y6-33", "The Professor of Forgotten Games", "🪀", 1220, "The playground games were dying, skipping rhymes garbled, marbles rules disputed, and the retired professor made it her emergency. She interviewed great-grandmothers like endangered archives, published the definitive rules of games no academy had thought worth ink, and refereed the revival tournaments herself, whistle and all. Her masterwork's dedication explains the urgency her colleagues mocked: civilisations keep their treaties in vaults and their childhoods in nothing but living memory. I have merely corrected the filing error.", "What did the professor preserve?", [["🎲","Playground games and rhymes"],["🏛️","Ancient treaties"],["🎨","Old paintings"]], 0),
  S("y6-34", "The Lamp in the Window", "🪔", 1230, "Every night for sixty years, a lamp burned in the cottage window above the cove, lit, everyone knew, for a fishing boat that never came home in 1953. What no one knew until the funeral: the keeper of the lamp had, decades in, begun receiving letters from strangers at sea, a tanker cook, a yachtswoman, a ferry hand, for whom her window was a fixed star on a dark coast. The lamp is electric now, on a timer, maintained by the parish. The letters still come. They are answered.", "Who wrote letters about the lamp?", [["⛵","Strangers at sea who steered by it"],["🏛️","The government"],["📰","Journalists"]], 0),
  S("y6-35", "The Recipe Without Measurements", "🥘", 1240, "The famous family dish defied transcription: a handful of this, cook until it sounds right, add the spice till the kitchen smells like Sunday. Food writers begged; the great-grandmother smiled. Her granddaughter finally understood the secret while learning at her elbow: the recipe was not imprecise, it was calibrated to a person, to her hands, her pans, her hearing. The published version, when it came, made culinary history with its honest first line: begin by spending ten years in the kitchen of someone who loves you.", "What was the recipe really calibrated to?", [["🙌","A person's own hands and senses"],["⚖️","Exact grams"],["⏲️","A timer"]], 0),
  S("y6-36", "The Peninsula of One House", "🏡", 1250, "The storm of 1987 cut the headland, leaving one farmhouse on a new tidal island, reachable twice a day. Authorities offered relocation; the family declined, renegotiating life around the moon instead: school by tide table, groceries by causeway window, guests informed that dinner invitations included, free of charge, the night. Their daughter's university essay about it, titled Punctuality Is a Lunar Concept, is taught in geography classes, mostly, she suspects, for the footnote: we were never cut off. The mainland was, twice a day, from us.", "How did the family see their situation?", [["🌙","The mainland was cut off from them"],["😢","As a disaster"],["💰","As a tourist business"]], 0),
  S("y6-37", "The Ninth Wave Pool", "🌊", 1260, "Generations of children at the cove were taught the count: waves run in families, and the ninth is the strong one. Physicists would quibble; grandmothers did not. The lifeguard station's log, kept since 1924, contains the count's vindications, rescues timed to the lull after the ninth, and one entry in a child's handwriting, entered solemnly by a guard who kept his word: today the ninth wave took my sandcastle. It was the best one. Logged so the sea knows we noticed.", "What did locals believe about the ninth wave?", [["💪","It was the strong one"],["🧊","It was the coldest"],["🐟","It carried fish"]], 0),
  S("y6-38", "The Borrowed Hundred", "💷", 1270, "The note in the museum case is ordinary: one hundred pounds, framed, with a letter. In 1931, a stranger at the railway station lent a ruined merchant his last hundred, asked his name only, and said, return it when the luck turns, to someone whose luck has not. The merchant rebuilt everything, never found the man, and honoured the terms forty-one times over, each loan with the same instruction. The museum traced the chain to over three thousand beneficiaries living. The display is titled with the only repayment the stranger ever specified: pass it on.", "What were the loan's repayment terms?", [["🔁","Pass it on to someone unlucky"],["🏦","Repay the bank"],["💰","Double the money back"]], 0),
  S("y6-39", "The Half-Hour Country", "⏰", 1280, "The valley ran thirty minutes behind the nation by stubborn custom, its clocks set to old solar time since the railways imposed the new. Bureaucrats sent letters; the valley sent back honey. Buses learned to print two timetables. Eventually anthropologists arrived to study what the valley had always known: the half hour was not lateness but a moat, and inside it, lunches lasted, conversations finished, and no one had ever profitably been hurried. The road sign at the pass, official now, reads: you are entering the half-hour country. Arrive when you arrive.", "What did the valley call its time difference?", [["🏰","A moat around their way of life"],["😴","Laziness"],["📐","A measuring error"]], 0),
  S("y6-40", "The Final Print Run", "🗞️", 1290, "The town paper's last edition, after 142 years, was set by hand on the original press, every working printer in three counties arriving unasked to help. The front page carried no news. It carried thanks: to the paperboys of seven generations, listed by route; to everyone ever misquoted, with apologies; to the town, for the privilege of paying attention to it. The edition sold eleven thousand copies in a town of four thousand, and the final line of the final column has been adopted by journalism schools as a benediction: we now return your stories to you. Tell them well.", "What did the last front page carry?", [["🙏","Thanks instead of news"],["📰","Breaking news"],["📷","Only photographs"]], 0),
  S("y6-41", "The Keeper of the Question Box", "❓", 1300, "The village school's question box predated living memory: any question, anonymous, answered each Friday by whoever the teacher judged best equipped, often another child. The archive of answered slips, discovered during renovations, now fills a published anthology. Its editors chose the title from a slip dated 1944, question and answer preserved together. Question: how do we go on when we are afraid? Answer, in a different child's hand: together, and by asking. The box is still in use. Friday remains, by common consent, the week's most important lesson.", "Who often answered the questions?", [["🧒","Another child"],["🤖","A computer"],["📚","An encyclopedia"]], 0),
  S("y6-42", "The Saltworks Choirmaster", "🧂", 1310, "The saltworks whistle had governed the town's days for a century, and when the works closed, silence sat strangely on the streets. The last foreman, unwilling to retire the sound, climbed weekly to blow the noon whistle for no shift at all, until the council, embarrassed into honesty, found it had become the most reliable thing in town. The whistle is listed now as working heritage. Its job description, drafted by the foreman before he died, is one sentence long: remind everyone, at noon, that they are in this together and it is time for lunch.", "Why did the foreman keep blowing the whistle?", [["🕛","The town needed its shared sound"],["💰","He was paid to"],["😡","To annoy the council"]], 0),
  S("y6-43", "The Garden of Failed Inventions", "⚙️", 1320, "The inventor's widow opened his workshop as a garden: the flying machine trellised with beans, the perpetual motion wheel turning compost, the automatic poet planted with forget-me-nots. Patent officers had rejected every device; the garden rejected the verdict. Schoolchildren tour it annually and are set the only assignment the widow permits: find what each failure is now succeeding at. The gate bears the inventor's own words, salvaged from his last notebook: nothing I built ever worked. Everything I built ever mattered.", "What grew on the flying machine?", [["🫘","Beans"],["🌹","Roses"],["🍇","Grapes"]], 0),
  S("y6-44", "The Sisters of the Semaphore", "🚩", 1330, "Before telephones reached the headlands, two sisters, postmistresses on facing cliffs, ran the strait's unofficial news service by semaphore flags: births, storms, ship sightings, and, famously, fifteen years of a courtship conducted entirely in code on behalf of a shy fisherman and a lighthouse keeper's daughter. The signal books they kept, donated at last by their estates, included one cipher never explained, used only between the sisters at each day's end. Cryptographers cracked it recently. It was, every evening for forty years, variations on a single message: well done today. Rest now.", "What was the sisters' nightly coded message?", [["💌","Well done today, rest now"],["⚠️","Storm warnings"],["💰","Market prices"]], 0),
  S("y6-45", "The Examination Hall Sparrow", "🐦", 1340, "Mid-way through the national examinations of 1976, a sparrow flew into the great hall, and the chief invigilator, in the decision of his career, announced: candidates will ignore the bird; the bird will be marked separately. Laughter settled nerves; results that year ran curiously high. The joke outlived him: every exam season since, the hall's corner table is laid with a card reading reserved, and senior students explain to juniors, with appropriate solemnity, that the sparrow has yet to collect its certificate, but attendance is always recorded.", "What did the invigilator announce?", [["😄","The bird will be marked separately"],["🚪","Evacuate the hall"],["🔁","The exam is cancelled"]], 0),
  S("y6-46", "The Library of Smallest Sounds", "🔉", 1350, "Her field recordings made no money and little sense to colleagues: a seed case opening, frost leaving a gate hinge, the specific hush of snow becoming rain. Universities declined the archive politely for years, until the soundscape ecologists arrived, hunting baselines for a quieting natural world, and found she had kept what no one else had thought to: the ordinary acoustic riches of a century's turn. The collection bears the name she always used for it, over the institute's objections and at her estate's insistence: things you would miss only afterwards.", "What did the recordist capture?", [["🌱","Tiny ordinary natural sounds"],["🎸","Rock concerts"],["🗣️","Famous speeches"]], 0),
  S("y6-47", "The Bridgekeeper's Census", "🌁", 1360, "For fifty years the bridgekeeper logged every crossing in his ledgers: not numbers, but reasons, gleaned from a tipped hat here, a tear there, a bouquet, a removal van. To hospital, hopeful. From the war, whole. Toward an apology, rehearsing. The bridge is automated now, sensors counting axles, and the transport authority concedes its data is poorer. His ledgers, archived complete, end with a final entry on retirement day, self-recorded as ever: across his bridge for the last time, slowly. Reason: everything.", "What did the bridgekeeper record about each crossing?", [["💭","The reason for it"],["🔢","Only the number"],["⏰","The exact time"]], 0),
  S("y6-48", "The Mended Constellation", "✨", 1370, "When light pollution erased the stars above the city, the planetarium's projector broke beyond repair the same winter, a coincidence the old astronomer refused to accept as an ending. She organised the Mending: ten thousand citizens, each assigned one star, each responsible for knowing it, its name, its distance, its stories, and for showing it to anyone who asked on the dark-sky bus trips out of town. The constellation map of responsibilities hangs in the city hall. The city, says the plaque beneath it, could not fix its sky, so it distributed the heavens among its citizens for safekeeping.", "What was each citizen assigned?", [["⭐","One star to know and share"],["🔭","A telescope"],["🚌","A bus route"]], 0),
  S("y6-49", "The Slow Letter Society", "🐌", 1380, "Founded in protest the year the telegraph reached town, the society's rules still stand: letters must take a month to write, an honest attempt at beautiful handwriting, and no news that will not keep. Membership dwindled to four in the email decade, then inexplicably swelled: students, programmers, a retired racing driver, all hungry, the chairwoman supposes, for sentences with patience in them. The society's archive holds the founding letter, its final line the membership oath to this day: I promise to believe that some things are worth the post.", "What is the society's rule for letters?", [["📅","They must take a month to write"],["⚡","They must be sent fast"],["🤐","They must be secret"]], 0),
  S("y6-50", "The Anniversary of Rain", "☔", 1390, "The drought broke on the fourth of June, 1923, after three failed harvests, and the town has kept the anniversary ever since: umbrellas carried regardless of forecast, gardens watered by hand at noon, a minute's appreciation observed at the fountain. Meteorologically meaningless, the university noted. The town agreed, and continued. Their children, asked by visiting reporters what is being celebrated, have given the same answer for a century, taught before spelling: that the worst thing ended, and that nobody who was there ever took weather, or anything else, for granted again.", "What do townspeople carry every fourth of June?", [["☂️","Umbrellas, whatever the forecast"],["🌾","Wheat sheaves"],["🕯️","Candles"]], 0),
];

const BY_INDEX: Story[][] = [YEAR1, YEAR2, YEAR3, YEAR4, YEAR5, YEAR6];

/** Hand-picked stories for a level. Extra arguments are kept so the old
    generator's call site stays unchanged. */
export function buildStories(
  _levelId: string,
  levelIndex: number,
  _lexLow: number,
  _lexHigh: number,
  _count?: number,
  _targetWords?: number,
): Story[] {
  return BY_INDEX[levelIndex] ?? BY_INDEX[BY_INDEX.length - 1];
}
